import { Card } from "@/components/Card";

interface Payload {
  prompt?: string;
  options?: string[];
}

interface Props {
  payload: Payload;
  /** Index of the currently selected option, or null before a tap. */
  selectedIndex: number | null;
  /** Called when the user picks an option — orchestrator auto-submits. */
  onPick: (index: number) => void;
  /** True while we're waiting for the grade response — disable further taps. */
  locked: boolean;
}

/**
 * Multiple choice — 4 options in a 2-column grid. Auto-submits via `onPick`.
 *
 * `locked` is set by the orchestrator while a grade request is in flight, so
 * a slow network doesn't let the user fire multiple submits.
 */
export function MultipleChoice({ payload, selectedIndex, onPick, locked }: Props) {
  const options = Array.isArray(payload.options) ? payload.options : [];

  return (
    <div className="flex flex-col gap-4 pt-2">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Выбери правильный вариант
      </p>
      <Card padding="md" className="text-center">
        <p className="text-base font-semibold text-slate-900">{payload.prompt ?? "—"}</p>
      </Card>
      <div className="grid grid-cols-2 gap-3">
        {options.map((opt, idx) => {
          const isPicked = selectedIndex === idx;
          return (
            <button
              key={`${idx}-${opt}`}
              type="button"
              disabled={locked}
              onClick={() => onPick(idx)}
              data-testid={`mcq-option-${idx}`}
              className={`min-h-[64px] rounded-2xl border-2 px-3 py-3 text-sm font-semibold transition-colors active:scale-[0.98] disabled:opacity-60 disabled:active:scale-100 ${
                isPicked
                  ? "border-terracotta bg-terracotta text-white"
                  : "border-slate-200 bg-white text-slate-900"
              }`}
            >
              {opt}
            </button>
          );
        })}
      </div>
    </div>
  );
}
