/**
 * Typed fetch client with JWT bearer + transparent 401-refresh.
 *
 * The auth store is the source of truth for tokens. We read tokens
 * synchronously from the store and import refresh lazily to avoid a circular
 * import (auth.ts uses apiFetch for /auth/refresh).
 */

import { useAuthStore } from "@/store/auth";
import type { ApiErrorBody } from "./types";

export const apiBase: string =
  (import.meta.env.VITE_API_BASE as string | undefined)?.replace(/\/$/, "") ??
  "http://localhost:8000";

export class ApiError extends Error {
  status: number;
  code: string | undefined;

  constructor(status: number, code: string | undefined, message: string) {
    super(message);
    this.name = "ApiError";
    this.status = status;
    this.code = code;
  }
}

interface FetchOptions extends RequestInit {
  /** Skip Authorization header. Used by /auth/telegram and /auth/refresh. */
  skipAuth?: boolean;
  /** Internal: prevents recursion if /auth/refresh itself 401s. */
  _retried?: boolean;
}

async function parseError(res: Response): Promise<ApiError> {
  let body: ApiErrorBody | null = null;
  try {
    body = (await res.json()) as ApiErrorBody;
  } catch {
    /* not JSON */
  }
  let code: string | undefined;
  let message = res.statusText || `HTTP ${res.status}`;
  if (body?.detail) {
    if (typeof body.detail === "string") {
      message = body.detail;
    } else {
      code = body.detail.code;
      message = body.detail.message ?? message;
    }
  }
  return new ApiError(res.status, code, message);
}

export async function apiFetch<T>(path: string, init: FetchOptions = {}): Promise<T> {
  const { skipAuth, _retried, headers, ...rest } = init;
  const url = path.startsWith("http") ? path : `${apiBase}${path}`;

  const finalHeaders: Record<string, string> = {
    Accept: "application/json",
    ...(rest.body && !(rest.body instanceof FormData) ? { "Content-Type": "application/json" } : {}),
    ...((headers as Record<string, string>) ?? {}),
  };

  if (!skipAuth) {
    const token = useAuthStore.getState().accessToken;
    if (token) finalHeaders["Authorization"] = `Bearer ${token}`;
  }

  const res = await fetch(url, { ...rest, headers: finalHeaders });

  if (res.status === 401 && !skipAuth && !_retried) {
    // Lazy import to break the import cycle with auth.ts.
    const { tryRefresh } = await import("./auth");
    const refreshed = await tryRefresh();
    if (refreshed) {
      return apiFetch<T>(path, { ...init, _retried: true });
    }
  }

  if (!res.ok) {
    throw await parseError(res);
  }

  // 204 No Content
  if (res.status === 204) return undefined as T;

  // Best-effort: backend may return empty body for some 200s.
  const text = await res.text();
  if (!text) return undefined as T;
  return JSON.parse(text) as T;
}
