import { useEffect, useMemo, useRef, useState } from "react";

interface RawPair {
  en?: string;
  ru?: string;
}

interface Payload {
  /** Source-of-truth pairs. Seed format is `{en, ru}` objects, but the grading
   *  layer also accepts `[en, ru]` 2-tuples — we tolerate both. */
  pairs?: Array<RawPair | [string, string]>;
}

interface Props {
  payload: Payload;
  /** Called once all pairs have been matched. Receives `[en, ru][]` in
   *  tap-order — that's exactly what the backend grader expects. */
  onComplete: (answer: string[][]) => void;
  locked: boolean;
}

interface NormalizedPair {
  en: string;
  ru: string;
}

function normalize(payload: Payload): NormalizedPair[] {
  const raw = Array.isArray(payload.pairs) ? payload.pairs : [];
  const out: NormalizedPair[] = [];
  for (const item of raw) {
    if (Array.isArray(item)) {
      const [en, ru] = item;
      if (typeof en === "string" && typeof ru === "string") out.push({ en, ru });
    } else if (item && typeof item === "object") {
      const en = (item as RawPair).en;
      const ru = (item as RawPair).ru;
      if (typeof en === "string" && typeof ru === "string") out.push({ en, ru });
    }
  }
  return out;
}

/**
 * Deterministic shuffle: returns `items` sorted by a stable hash of their
 * value + a salt, so the two columns appear in different orders without
 * needing `Math.random` (which would re-shuffle on every re-render).
 */
function stableShuffle<T extends { key: string }>(items: T[], salt: string): T[] {
  const hashed = items.map((it) => ({
    it,
    h: cyrb53(it.key + salt),
  }));
  hashed.sort((a, b) => a.h - b.h);
  return hashed.map((x) => x.it);
}

// Small, fast 53-bit string hash — enough for layout randomisation.
function cyrb53(str: string): number {
  let h1 = 0xdeadbeef ^ 0;
  let h2 = 0x41c6ce57 ^ 0;
  for (let i = 0; i < str.length; i += 1) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return 4294967296 * (2097151 & h2) + (h1 >>> 0);
}

type Status = "idle" | "wrong";

/**
 * Match-pairs UI state model:
 *  - `matched: Set<string>` keeps which `pair.en` keys are already resolved.
 *  - `pickedEn: string | null` is the currently selected EN card (left col).
 *    Tapping an RU card resolves the attempt:
 *      • correct → both fade out (CSS), pair recorded in `taps`.
 *      • wrong   → brief red flash on both, then reset.
 *  - `taps: [en, ru][]` is the answer we'll ship to the backend.
 *
 * Scoping note: all of the above is local to this component — the
 * orchestrator only learns the final answer via `onComplete`. This avoids
 * leaking transient interactive state up the tree.
 */
export function MatchPairs({ payload, onComplete, locked }: Props) {
  const pairs = useMemo(() => normalize(payload), [payload]);
  const enList = useMemo(
    () =>
      stableShuffle(
        pairs.map((p) => ({ key: p.en, label: p.en })),
        "en",
      ),
    [pairs],
  );
  const ruList = useMemo(
    () =>
      stableShuffle(
        pairs.map((p) => ({ key: p.en, label: p.ru })),
        "ru",
      ),
    [pairs],
  );

  const [pickedEn, setPickedEn] = useState<string | null>(null);
  const [matched, setMatched] = useState<Set<string>>(() => new Set());
  const [wrongPair, setWrongPair] = useState<{ en: string; ru: string } | null>(null);
  const [status, setStatus] = useState<Status>("idle");
  const tapsRef = useRef<string[][]>([]);
  const wrongTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    return () => {
      if (wrongTimerRef.current) clearTimeout(wrongTimerRef.current);
    };
  }, []);

  // When everything's matched, ship the answer up exactly once.
  const totalPairs = pairs.length;
  const allMatched = totalPairs > 0 && matched.size === totalPairs;
  useEffect(() => {
    if (allMatched) {
      onComplete(tapsRef.current.map((p) => [...p]));
    }
    // We intentionally depend only on `allMatched`; `onComplete` is stable
    // enough (parent uses useCallback or a fresh closure per render — either
    // way we want exactly one fire on the matched→true edge).
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [allMatched]);

  const lookupRu = (enKey: string): string | undefined =>
    pairs.find((p) => p.en === enKey)?.ru;

  const onTapEn = (enKey: string): void => {
    if (locked || status === "wrong" || matched.has(enKey)) return;
    setPickedEn((prev) => (prev === enKey ? null : enKey));
  };

  const onTapRu = (enKey: string, ruLabel: string): void => {
    if (locked || status === "wrong" || matched.has(enKey)) return;
    if (pickedEn === null) return;

    const expectedRu = lookupRu(pickedEn);
    if (expectedRu === ruLabel) {
      // Correct
      const next = new Set(matched);
      next.add(pickedEn);
      tapsRef.current.push([pickedEn, ruLabel]);
      setMatched(next);
      setPickedEn(null);
    } else {
      // Wrong — flash both for 500ms, then reset selection.
      setWrongPair({ en: pickedEn, ru: enKey });
      setStatus("wrong");
      wrongTimerRef.current = setTimeout(() => {
        setStatus("idle");
        setWrongPair(null);
        setPickedEn(null);
      }, 500);
    }
  };

  return (
    <div className="flex flex-col gap-4 pt-2">
      <style>{`
        @keyframes lingomy-pair-flash {
          0%, 100% { background-color: #fee2e2; border-color: #ef4444; }
          50% { background-color: #fecaca; border-color: #dc2626; }
        }
        .pair-wrong { animation: lingomy-pair-flash 0.5s ease-in-out; }
        .pair-fade { opacity: 0; pointer-events: none; transition: opacity 250ms ease-out; }
      `}</style>

      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Соедини пары
      </p>

      <div className="grid grid-cols-2 gap-3">
        {/* EN column */}
        <div className="flex flex-col gap-2">
          {enList.map(({ key, label }) => {
            const isMatched = matched.has(key);
            const isPicked = pickedEn === key;
            const isWrong = wrongPair?.en === key;
            return (
              <button
                key={`en-${key}`}
                type="button"
                disabled={isMatched || locked}
                onClick={() => onTapEn(key)}
                data-testid={`pair-en-${key}`}
                className={`min-h-[56px] rounded-2xl border-2 px-3 py-2 text-sm font-semibold transition-all active:scale-[0.98] ${
                  isMatched
                    ? "pair-fade border-slate-200 bg-white text-slate-300"
                    : isWrong
                      ? "pair-wrong border-red-500 bg-red-100 text-slate-900"
                      : isPicked
                        ? "border-terracotta bg-cream-100 text-slate-900 ring-2 ring-terracotta"
                        : "border-slate-200 bg-white text-slate-900"
                }`}
              >
                {label}
              </button>
            );
          })}
        </div>

        {/* RU column */}
        <div className="flex flex-col gap-2">
          {ruList.map(({ key, label }) => {
            const isMatched = matched.has(key);
            const isWrong = wrongPair?.ru === key;
            return (
              <button
                key={`ru-${key}`}
                type="button"
                disabled={isMatched || locked}
                onClick={() => onTapRu(key, label)}
                data-testid={`pair-ru-${key}`}
                className={`min-h-[56px] rounded-2xl border-2 px-3 py-2 text-sm font-semibold transition-all active:scale-[0.98] ${
                  isMatched
                    ? "pair-fade border-slate-200 bg-white text-slate-300"
                    : isWrong
                      ? "pair-wrong border-red-500 bg-red-100 text-slate-900"
                      : "border-slate-200 bg-white text-slate-900"
                }`}
              >
                {label}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}
