import { useLocation } from "wouter";

const TABS = [
  { path: "/tree", label: "Уроки", icon: "📚" },
  { path: "/league", label: "Лига", icon: "🏆" },
  { path: "/friends", label: "Друзья", icon: "👥" },
  { path: "/profile", label: "Профиль", icon: "👤" },
] as const;

export function BottomNav() {
  const [location, navigate] = useLocation();

  return (
    <nav className="flex border-t border-slate-200 bg-white">
      {TABS.map((tab) => {
        const active = location === tab.path || (tab.path === "/tree" && location === "/");
        return (
          <button
            key={tab.path}
            onClick={() => navigate(tab.path)}
            className={`flex flex-1 flex-col items-center gap-0.5 py-2 text-xs font-medium transition-colors ${
              active ? "text-amber-500" : "text-slate-400"
            }`}
          >
            <span className="text-xl leading-none">{tab.icon}</span>
            {tab.label}
          </button>
        );
      })}
    </nav>
  );
}
