import { useQuery } from "@tanstack/react-query";

import { apiFetch } from "@/lib/api";
import type {
  HeartsResponse,
  MeResponse,
  StreakResponse,
  XpStatsResponse,
} from "@/lib/types";
import { Card } from "@/components/Card";
import { Screen } from "@/components/Screen";
import { Loading } from "@/components/Loading";
import { ErrorBox } from "@/components/ErrorBox";

/* ------------------------------- Helpers -------------------------------- */

const TIER_LABEL: Record<string, string> = {
  free: "Beta",
  trial: "Beta",
  premium: "Premium",
};

const TIER_CLASSES: Record<string, string> = {
  free: "bg-slate-200 text-slate-700",
  trial: "bg-amber-100 text-amber-800",
  premium: "bg-terracotta-100 text-terracotta-700",
};

const LEAGUE_LABEL: Record<string, string> = {
  bronze: "Бронза",
  silver: "Серебро",
  gold: "Золото",
  sapphire: "Сапфир",
  ruby: "Рубин",
  diamond: "Алмаз",
};

const LEAGUE_CLASSES: Record<string, string> = {
  bronze: "bg-[#B26A3C]/15 text-[#B26A3C]",
  silver: "bg-slate-300/40 text-slate-700",
  gold: "bg-[#D4A21A]/15 text-[#D4A21A]",
  sapphire: "bg-[#3B6AC4]/15 text-[#3B6AC4]",
  ruby: "bg-[#C73762]/15 text-[#C73762]",
  diamond: "bg-[#6FB8C9]/20 text-[#3F8A9C]",
};

function avatarLetter(username: string | null | undefined, telegramId: number): string {
  const s = (username ?? "").trim();
  if (s) return s.charAt(0).toUpperCase();
  // fallback: first digit of telegram id
  return String(telegramId).charAt(0);
}

function formatCountdown(iso: string | null): string | null {
  if (!iso) return null;
  const target = new Date(iso).getTime();
  if (!Number.isFinite(target)) return null;
  const diff = target - Date.now();
  if (diff <= 0) return "почти готово";
  const mins = Math.floor(diff / 60_000);
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  if (h >= 1) return `${h} ч ${m} мин`;
  return `${m} мин`;
}

/* -------------------------------- Atoms --------------------------------- */

function KpiCard({
  label,
  value,
  emoji,
  accent,
}: {
  label: string;
  value: string | number;
  emoji?: string;
  accent?: "warm" | "cool" | "neutral";
}) {
  const accentCls =
    accent === "warm"
      ? "text-terracotta"
      : accent === "cool"
        ? "text-[#3B6AC4]"
        : "text-slate-900";
  return (
    <Card padding="md" className="flex flex-1 flex-col gap-1">
      <div className="flex items-baseline justify-between">
        <span className={`text-2xl font-bold tracking-tight ${accentCls}`}>{value}</span>
        {emoji && <span className="text-lg">{emoji}</span>}
      </div>
      <span className="text-xs font-medium uppercase tracking-wide text-slate-500">{label}</span>
    </Card>
  );
}

function HeartsRow({ hearts }: { hearts: HeartsResponse }) {
  const filled = "❤️";
  const empty = "🤍";
  // Render at most 10 hearts on the row even if max_hearts == 999 (Premium).
  const visualMax = Math.min(hearts.max_hearts, 10);
  const visualHearts = Math.min(hearts.hearts, visualMax);
  const countdown =
    hearts.hearts < hearts.max_hearts ? formatCountdown(hearts.regen_at) : null;

  return (
    <Card padding="md" className="flex flex-col gap-3">
      <div className="flex items-center justify-between">
        <span className="text-sm font-semibold text-slate-900">Сердечки</span>
        <span className="text-sm tabular-nums text-slate-600">
          {hearts.hearts}
          {hearts.max_hearts < 100 ? ` / ${hearts.max_hearts}` : " / ∞"}
        </span>
      </div>
      <div className="flex flex-wrap gap-1.5 text-lg leading-none">
        {Array.from({ length: visualMax }).map((_, i) => (
          <span key={i}>{i < visualHearts ? filled : empty}</span>
        ))}
      </div>
      {countdown && (
        <p className="text-xs text-slate-500">
          Следующее сердечко через <span className="font-medium text-slate-700">{countdown}</span>
        </p>
      )}
      {hearts.max_hearts >= 100 && (
        <p className="text-xs text-slate-500">Безлимит — спасибо за Premium 🙌</p>
      )}
    </Card>
  );
}

/* ------------------------------- Screen --------------------------------- */

export function Profile() {
  const meQ = useQuery<MeResponse>({
    queryKey: ["me"],
    queryFn: () => apiFetch<MeResponse>("/me"),
  });
  const xpQ = useQuery<XpStatsResponse>({
    queryKey: ["xp"],
    queryFn: () => apiFetch<XpStatsResponse>("/xp"),
  });
  const streakQ = useQuery<StreakResponse>({
    queryKey: ["streak"],
    queryFn: () => apiFetch<StreakResponse>("/streak"),
  });
  const heartsQ = useQuery<HeartsResponse>({
    queryKey: ["hearts"],
    queryFn: () => apiFetch<HeartsResponse>("/hearts"),
  });

  const queries = [meQ, xpQ, streakQ, heartsQ];
  const isLoading = queries.some((q) => q.isLoading);
  const error = queries.find((q) => q.error)?.error;

  if (isLoading) {
    return (
      <Screen title="Профиль">
        <Loading />
      </Screen>
    );
  }

  if (error || !meQ.data || !xpQ.data || !streakQ.data || !heartsQ.data) {
    return (
      <Screen title="Профиль">
        <ErrorBox
          message={(error as Error)?.message ?? "Не удалось загрузить профиль"}
          onRetry={() => {
            void meQ.refetch();
            void xpQ.refetch();
            void streakQ.refetch();
            void heartsQ.refetch();
          }}
        />
      </Screen>
    );
  }

  const me = meQ.data;
  const xp = xpQ.data;
  const streak = streakQ.data;
  const hearts = heartsQ.data;

  const displayName = me.username ? `@${me.username}` : `id${me.telegram_id}`;
  const tierKey = me.tier in TIER_LABEL ? me.tier : "free";
  const leagueKey = me.league_tier && me.league_tier in LEAGUE_LABEL ? me.league_tier : null;

  return (
    <Screen title="Профиль">
      <div className="flex flex-col gap-4">
        {/* ------ Identity block ------ */}
        <div className="flex flex-col items-center gap-3 pt-2">
          <div className="flex h-24 w-24 items-center justify-center rounded-full bg-terracotta text-4xl font-bold text-white shadow-card">
            {avatarLetter(me.username, me.telegram_id)}
          </div>
          <div className="flex flex-col items-center gap-1.5">
            <h2 className="text-lg font-semibold text-slate-900">{displayName}</h2>
            <div className="flex items-center gap-2">
              <span className={`lg-pill ${TIER_CLASSES[tierKey]}`}>{TIER_LABEL[tierKey]}</span>
              {leagueKey && (
                <span className={`lg-pill ${LEAGUE_CLASSES[leagueKey]}`}>
                  Лига: {LEAGUE_LABEL[leagueKey]}
                </span>
              )}
            </div>
          </div>
        </div>

        {/* ------ KPI cards ------ */}
        <div className="flex flex-row gap-3">
          <KpiCard label="Стрик" value={streak.current_streak} emoji="🔥" accent="warm" />
          <KpiCard label="XP сегодня" value={xp.today_xp} emoji="⭐" accent="neutral" />
          <KpiCard label="XP за неделю" value={xp.week_xp} emoji="📈" accent="cool" />
        </div>

        {/* ------ Hearts ------ */}
        <HeartsRow hearts={hearts} />

        {/* ------ Misc / extra info ------ */}
        <Card padding="md" className="flex flex-col gap-2">
          <div className="flex items-center justify-between text-sm">
            <span className="text-slate-500">Лучший стрик</span>
            <span className="font-medium text-slate-900">{streak.longest_streak} 🔥</span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="text-slate-500">XP за месяц</span>
            <span className="font-medium text-slate-900">{xp.month_xp}</span>
          </div>
          <div className="flex items-center justify-between text-sm">
            <span className="text-slate-500">XP всего</span>
            <span className="font-medium text-slate-900">{xp.lifetime_xp}</span>
          </div>
        </Card>
      </div>
    </Screen>
  );
}
