import { Card } from "@/components/Card";

interface Payload {
  prompt_ru?: string;
  word_bank?: string[];
}

interface Props {
  payload: Payload;
  /** Tokens placed by the user, in order. */
  assembled: string[];
  /** Tokens still in the bank, in original payload order minus assembled. */
  bank: string[];
  onAssembledChange: (next: string[]) => void;
  onBankChange: (next: string[]) => void;
}

/**
 * Translate from Russian to English with a word-bank.
 *
 * State design: the parent holds two arrays (assembled + bank). Tapping a
 * bank chip moves it to assembled; tapping an assembled chip returns it to
 * the bank. Duplicates in the word-bank are supported by indexing tokens —
 * we attach a stable key per occurrence via the index in the original bank.
 */
export function TranslateRuEn({
  payload,
  assembled,
  bank,
  onAssembledChange,
  onBankChange,
}: Props) {
  const onTapBank = (idx: number): void => {
    const token = bank[idx];
    if (token === undefined) return;
    onBankChange([...bank.slice(0, idx), ...bank.slice(idx + 1)]);
    onAssembledChange([...assembled, token]);
  };

  const onTapAssembled = (idx: number): void => {
    const token = assembled[idx];
    if (token === undefined) return;
    onAssembledChange([...assembled.slice(0, idx), ...assembled.slice(idx + 1)]);
    onBankChange([...bank, token]);
  };

  return (
    <div className="flex flex-col gap-4 pt-2">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Переведи на английский
      </p>
      <Card padding="md" className="text-center">
        <p className="text-lg font-semibold text-slate-900">{payload.prompt_ru ?? "—"}</p>
      </Card>

      {/* Assembled row — keeps a minimum height so the layout doesn't jump. */}
      <div
        className="flex min-h-[64px] flex-wrap items-start gap-2 rounded-2xl border-2 border-dashed border-slate-300 bg-cream-100 p-3"
        data-testid="assembled-row"
      >
        {assembled.length === 0 && (
          <span className="text-sm text-slate-400">Собери предложение…</span>
        )}
        {assembled.map((tok, i) => (
          <button
            key={`a-${i}-${tok}`}
            type="button"
            onClick={() => onTapAssembled(i)}
            className="rounded-full bg-terracotta px-3.5 py-1.5 text-sm font-semibold text-white shadow-sm active:scale-[0.98]"
          >
            {tok}
          </button>
        ))}
      </div>

      {/* Bank */}
      <div className="flex flex-wrap items-start gap-2">
        {bank.map((tok, i) => (
          <button
            key={`b-${i}-${tok}`}
            type="button"
            onClick={() => onTapBank(i)}
            className="rounded-full border border-slate-200 bg-white px-3.5 py-1.5 text-sm font-semibold text-slate-900 shadow-card active:scale-[0.98]"
          >
            {tok}
          </button>
        ))}
      </div>
    </div>
  );
}
