import type { ReactNode } from "react";

import { Button } from "@/components/Button";

interface StepCardProps {
  /** 0-based step index within the lesson. */
  stepIndex: number;
  /** Total number of steps in the lesson (for the progress bar). */
  totalSteps: number;
  /** Hearts remaining as last known from the backend. Hidden when null. */
  heartsRemaining: number | null;
  /** Step body (one per step type). */
  children: ReactNode;
  /** CTA label, e.g. "Проверить" / "Дальше". */
  ctaLabel: string;
  /** CTA active flag — controls disabled state. */
  ctaEnabled: boolean;
  /** CTA click handler. */
  onCta: () => void;
  /** Optional override of CTA visibility — match_pairs / multiple_choice auto-submit. */
  hideCta?: boolean;
}

/**
 * Shared chrome for every step type: progress bar + hearts badge on top, a
 * body slot in the middle, and a sticky CTA at the bottom.
 *
 * Why a single component:
 *  - Keeps the visual rhythm consistent (same paddings, same CTA placement).
 *  - Centralises the "disable while just-rendered" guard for the CTA by
 *    making the parent always pass `ctaEnabled` explicitly per step.
 */
export function StepCard({
  stepIndex,
  totalSteps,
  heartsRemaining,
  children,
  ctaLabel,
  ctaEnabled,
  onCta,
  hideCta = false,
}: StepCardProps) {
  const progress = totalSteps > 0 ? ((stepIndex + 1) / totalSteps) * 100 : 0;

  return (
    <div className="flex h-full flex-col">
      {/* Top bar: progress + hearts */}
      <div className="flex items-center gap-3 px-1 pb-3">
        <div
          className="h-2 flex-1 overflow-hidden rounded-full bg-cream-300"
          role="progressbar"
          aria-valuemin={0}
          aria-valuemax={totalSteps}
          aria-valuenow={stepIndex + 1}
        >
          <div
            className="h-full rounded-full bg-terracotta transition-[width] duration-300 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
        {heartsRemaining !== null && (
          <div
            className="flex items-center gap-1 rounded-full bg-white px-2.5 py-1 text-sm font-semibold text-slate-900 shadow-card"
            aria-label={`Сердечек осталось: ${heartsRemaining}`}
          >
            <span aria-hidden="true">❤️</span>
            <span className="tabular-nums">{heartsRemaining}</span>
          </div>
        )}
      </div>

      {/* Body */}
      <div className="flex-1 overflow-y-auto pb-4">{children}</div>

      {/* CTA */}
      {!hideCta && (
        <div className="pt-3">
          <Button
            type="button"
            size="lg"
            className="w-full"
            disabled={!ctaEnabled}
            onClick={onCta}
          >
            {ctaLabel}
          </Button>
        </div>
      )}
    </div>
  );
}
