/**
 * League tier lookup table.
 *
 * Six tiers ordered by `sort_order` (bronze=lowest → diamond=highest).
 * Emoji choices avoid using the same gem twice: bronze/silver/gold use the
 * standard medal series; sapphire is the blue gem (no separate sapphire
 * emoji exists, so we use the closest visual match), ruby uses a red gem,
 * diamond uses the white diamond. Russian labels match the bot UI strings.
 */
import type { LeagueTier } from "@/lib/types";

export interface TierMeta {
  slug: LeagueTier;
  label_ru: string;
  emoji: string;
  /** Accent color used for the tier pill / header glyph. */
  color: string;
  sort_order: number;
}

export const TIER_META: Record<LeagueTier, TierMeta> = {
  bronze: {
    slug: "bronze",
    label_ru: "Бронза",
    emoji: "\u{1F949}", // 🥉
    color: "#B26A3C",
    sort_order: 1,
  },
  silver: {
    slug: "silver",
    label_ru: "Серебро",
    emoji: "\u{1F948}", // 🥈
    color: "#9CA3AF",
    sort_order: 2,
  },
  gold: {
    slug: "gold",
    label_ru: "Золото",
    emoji: "\u{1F947}", // 🥇
    color: "#D4A21A",
    sort_order: 3,
  },
  sapphire: {
    slug: "sapphire",
    label_ru: "Сапфир",
    emoji: "\u{1F537}", // 🔷 (blue large diamond — closest to sapphire)
    color: "#3B6AC4",
    sort_order: 4,
  },
  ruby: {
    slug: "ruby",
    label_ru: "Рубин",
    emoji: "\u{2764}\u{FE0F}", // ❤️
    color: "#C73762",
    sort_order: 5,
  },
  diamond: {
    slug: "diamond",
    label_ru: "Бриллиант",
    emoji: "\u{1F48E}", // 💎
    color: "#6FB8C9",
    sort_order: 6,
  },
};

const KNOWN_TIERS = new Set<string>(Object.keys(TIER_META));

/** Best-effort lookup with a sensible bronze fallback for unexpected slugs. */
export function getTierMeta(tier: string): TierMeta {
  if (KNOWN_TIERS.has(tier)) {
    return TIER_META[tier as LeagueTier];
  }
  return TIER_META.bronze;
}
