import { Card } from "@/components/Card";

interface Payload {
  prompt_en?: string;
}

interface Props {
  payload: Payload;
  value: string;
  onChange: (v: string) => void;
}

/** Translate from English to Russian — free-form textarea. */
export function TranslateEnRu({ payload, value, onChange }: Props) {
  return (
    <div className="flex flex-col gap-4 pt-2">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Переведи на русский
      </p>
      <Card padding="lg" className="text-center">
        <p className="text-2xl font-semibold text-slate-900">{payload.prompt_en ?? "—"}</p>
      </Card>
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        rows={3}
        placeholder="Твой ответ..."
        autoComplete="off"
        autoCorrect="off"
        spellCheck={false}
        className="w-full resize-none rounded-2xl border border-slate-200 bg-white p-3 text-base text-slate-900 shadow-card outline-none focus:border-terracotta"
      />
    </div>
  );
}
