import type { FriendshipOut } from "./types";

/** First letter for the avatar circle; falls back to the last digit of telegram_id. */
export function avatarLetter(username: string | null | undefined, userId: number): string {
  const s = (username ?? "").trim();
  if (s) return s.charAt(0).toUpperCase();
  return String(userId).slice(-1);
}

/** Display name; falls back to "Игрок #<last 4>" so the row never shows raw IDs. */
export function displayName(username: string | null | undefined, userId: number): string {
  const s = (username ?? "").trim();
  if (s) return s;
  const last4 = String(userId).slice(-4);
  return `Игрок #${last4}`;
}

/** Russian-friendly short date: "12 мая 2025". */
export function formatRuDate(iso: string | null | undefined): string {
  if (!iso) return "—";
  const d = new Date(iso);
  if (!Number.isFinite(d.getTime())) return "—";
  return d.toLocaleDateString("ru-RU", { day: "numeric", month: "long", year: "numeric" });
}

/** Sort accepted friendships alphabetically by display name. */
export function sortFriends(rows: FriendshipOut[]): FriendshipOut[] {
  return [...rows].sort((a, b) =>
    displayName(a.username, a.friend_id).localeCompare(displayName(b.username, b.friend_id), "ru"),
  );
}
