/**
 * Small audio playback helper for lesson steps.
 *
 * The backend serves TTS files from `/audio/<filename>` (relative to the API
 * base, or an explicit `VITE_AUDIO_BASE` if the audio CDN ever splits off).
 * The route may not exist yet — `playAudio` swallows the resulting load /
 * decode errors so the step UI never crashes when audio is missing.
 *
 * Only one HTMLAudioElement is active at a time: kicking off a new clip
 * pauses the previous one so the user never hears two voices at once.
 */

const DEFAULT_API_BASE = "http://localhost:8000";

function audioBase(): string {
  const explicit = import.meta.env.VITE_AUDIO_BASE;
  if (explicit) return explicit.replace(/\/$/, "");
  const api = import.meta.env.VITE_API_BASE;
  if (api) return api.replace(/\/$/, "");
  return DEFAULT_API_BASE;
}

export function audioUrl(filename: string): string {
  return `${audioBase()}/audio/${encodeURIComponent(filename)}`;
}

let currentAudio: HTMLAudioElement | null = null;

/**
 * Play the named audio file once. Resolves when playback starts (NOT when it
 * finishes — we don't need to await full playback to keep the UI responsive).
 * Rejected promises are swallowed by the caller: a missing audio file should
 * never block the user from continuing the lesson.
 */
export async function playAudio(filename: string): Promise<void> {
  if (!filename) return;
  try {
    if (currentAudio) {
      currentAudio.pause();
      currentAudio.src = "";
      currentAudio = null;
    }
    const el = new Audio(audioUrl(filename));
    currentAudio = el;
    await el.play();
  } catch (e) {
    // 404 / decode error / autoplay-blocked — nothing actionable for the user.
    // eslint-disable-next-line no-console
    console.warn("[audio] playback failed:", e);
  }
}
