import { useQuery } from "@tanstack/react-query";

import { apiFetch } from "@/lib/api";
import { Card } from "@/components/Card";
import { Loading } from "@/components/Loading";
import { ErrorBox } from "@/components/ErrorBox";
import { useAuthStore } from "@/store/auth";

import type { FriendsLeaderboardResponse } from "./types";
import { avatarLetter, displayName } from "./util";

export function FriendsLeaderboard() {
  const viewerId = useAuthStore((s) => s.telegramId);
  const q = useQuery<FriendsLeaderboardResponse>({
    queryKey: ["friends", "leaderboard"],
    queryFn: () => apiFetch<FriendsLeaderboardResponse>("/friends/leaderboard"),
  });

  if (q.isLoading) return <Loading label="Загрузка топа..." />;
  if (q.error || !q.data) {
    return (
      <ErrorBox
        message={(q.error as Error)?.message ?? "Не удалось загрузить топ"}
        onRetry={() => void q.refetch()}
      />
    );
  }

  const rows = q.data.rows ?? [];
  // "Has no friends" heuristic: only the viewer themselves shows up.
  const onlySelf = rows.length <= 1 && rows.every((r) => r.user_id === viewerId);

  if (rows.length === 0 || onlySelf) {
    return (
      <Card padding="lg" className="text-center">
        <p className="text-sm text-slate-600">Добавь друзей, чтобы соревноваться.</p>
      </Card>
    );
  }

  return (
    <ul className="flex flex-col gap-1.5">
      {rows.map((row) => {
        const isMe = row.user_id === viewerId;
        const name = displayName(row.username, row.user_id);
        return (
          <li key={row.user_id}>
            <Card
              padding="md"
              className={`flex items-center gap-3 ${
                isMe ? "ring-2 ring-terracotta" : ""
              }`}
            >
              <span className="w-7 shrink-0 text-center text-sm font-bold tabular-nums text-slate-500">
                {row.rank}
              </span>
              <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-full bg-cream-300 text-sm font-bold text-slate-700">
                {avatarLetter(row.username, row.user_id)}
              </div>
              <div className="flex min-w-0 flex-1 flex-col">
                <span className="truncate text-sm font-semibold text-slate-900">
                  {name}
                  {isMe && <span className="ml-1.5 text-xs text-terracotta">(ты)</span>}
                </span>
              </div>
              <span className="shrink-0 text-sm font-semibold tabular-nums text-slate-900">
                {row.weekly_xp} XP
              </span>
            </Card>
          </li>
        );
      })}
    </ul>
  );
}
