import { useCallback, useEffect, useState } from "react";
import { useLocation, useParams } from "wouter";

import { ApiError, apiFetch } from "@/lib/api";
import { Button } from "@/components/Button";
import { ErrorBox } from "@/components/ErrorBox";
import { Loading } from "@/components/Loading";
import { Screen } from "@/components/Screen";

import { StepCard } from "@/lessons/StepCard";
import { Summary } from "@/lessons/Summary";
import { FillBlank } from "@/lessons/steps/FillBlank";
import { ListenType } from "@/lessons/steps/ListenType";
import { MatchPairs } from "@/lessons/steps/MatchPairs";
import { MultipleChoice } from "@/lessons/steps/MultipleChoice";
import { TranslateEnRu } from "@/lessons/steps/TranslateEnRu";
import { TranslateRuEn } from "@/lessons/steps/TranslateRuEn";
import { VocabIntro } from "@/lessons/steps/VocabIntro";
import type {
  CompleteLessonResponse,
  GradeAnswer,
  GradeStepResponse,
  StartLessonResponse,
  StepOut,
  StepType,
} from "@/lessons/types";

/* ===========================================================================
 * State machine
 *
 *   boot        → /lessons/:id/start
 *   step        → user works on a step, CTA submits
 *   grading     → /steps/:id/grade in flight
 *   result      → green/red overlay shown, CTA moves to next step
 *   completing  → /lessons/:id/complete in flight
 *   summary     → end screen
 *   no-hearts   → 403 NO_HEARTS overlay
 *   error       → generic error screen
 *
 * The current step index is plain state. We never mutate `start.steps` after
 * boot — that array is the source of truth for the lesson body.
 * =========================================================================*/

type Phase =
  | { kind: "boot" }
  | { kind: "step"; stepIndex: number }
  | { kind: "grading"; stepIndex: number }
  | {
      kind: "result";
      stepIndex: number;
      grade: GradeStepResponse;
    }
  | { kind: "completing" }
  | { kind: "summary"; result: CompleteLessonResponse }
  | { kind: "no-hearts" }
  | { kind: "error"; message: string };

/* --------------------------- Per-step answer state ---------------------- */
/**
 * One blob of "in-progress" state per step type. We hold them all in a
 * single `answers` record keyed by step index so that returning to a step
 * (we don't today, but cheap to support) would not lose the input. The map
 * also keeps the answer types straight in TS without prop-drilling unions.
 */
interface AnswerState {
  text?: string;
  selectedIndex?: number | null;
  selectedOption?: string | null;
  assembled?: string[];
  bank?: string[];
  pairs?: string[][];
}

function defaultAnswerFor(step: StepOut): AnswerState {
  if (step.step_type === "translate_ru_en") {
    const bankRaw = (step.payload_json as { word_bank?: unknown }).word_bank;
    const bank = Array.isArray(bankRaw)
      ? bankRaw.filter((x): x is string => typeof x === "string")
      : [];
    return { assembled: [], bank };
  }
  if (step.step_type === "multiple_choice") return { selectedIndex: null };
  if (step.step_type === "fill_blank") return { selectedOption: null };
  if (step.step_type === "match_pairs") return { pairs: [] };
  return { text: "" };
}

/* -------------------------------- Screen -------------------------------- */

export function Lesson() {
  const params = useParams<{ id: string }>();
  const lessonId = Number(params.id);
  const [, navigate] = useLocation();

  const [phase, setPhase] = useState<Phase>({ kind: "boot" });
  const [start, setStart] = useState<StartLessonResponse | null>(null);
  const [answers, setAnswers] = useState<Record<number, AnswerState>>({});
  const [heartsRemaining, setHeartsRemaining] = useState<number | null>(null);
  const [showResumeToast, setShowResumeToast] = useState(false);

  /** Guards the CTA against the user mashing it right as a step renders. */
  const [ctaArmed, setCtaArmed] = useState(false);

  // Boot — start the lesson on mount.
  useEffect(() => {
    if (!Number.isFinite(lessonId)) {
      setPhase({ kind: "error", message: "Некорректный идентификатор урока" });
      return;
    }
    let cancelled = false;

    (async () => {
      try {
        const res = await apiFetch<StartLessonResponse>(
          `/lessons/${lessonId}/start`,
          { method: "POST", body: JSON.stringify({}) },
        );
        if (cancelled) return;
        setStart(res);
        // Seed answer state for every step up front.
        const seeded: Record<number, AnswerState> = {};
        res.steps.forEach((s, i) => {
          seeded[i] = defaultAnswerFor(s);
        });
        setAnswers(seeded);
        if (res.already_in_progress) {
          setShowResumeToast(true);
          window.setTimeout(() => setShowResumeToast(false), 1500);
        }
        if (res.steps.length === 0) {
          // No steps — go straight to complete (a content bug, but
          // defensively handled so the user can still press "back").
          void completeLesson();
        } else {
          setPhase({ kind: "step", stepIndex: 0 });
        }
      } catch (e) {
        if (cancelled) return;
        if (e instanceof ApiError && e.status === 403 && e.code === "NO_HEARTS") {
          setPhase({ kind: "no-hearts" });
        } else {
          setPhase({
            kind: "error",
            message: e instanceof Error ? e.message : "Не удалось начать урок",
          });
        }
      }
    })();

    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [lessonId]);

  // Re-arm the CTA whenever we land on a fresh step. A 250ms cooldown
  // prevents the previous-step "Дальше" tap from re-firing the new step's
  // submit before the user actually sees the new content.
  useEffect(() => {
    if (phase.kind !== "step") return;
    setCtaArmed(false);
    const t = window.setTimeout(() => setCtaArmed(true), 250);
    return () => window.clearTimeout(t);
  }, [phase]);

  const completeLesson = useCallback(async () => {
    setPhase({ kind: "completing" });
    try {
      const res = await apiFetch<CompleteLessonResponse>(
        `/lessons/${lessonId}/complete`,
        { method: "POST", body: JSON.stringify({}) },
      );
      setPhase({ kind: "summary", result: res });
    } catch (e) {
      if (e instanceof ApiError && e.status === 403 && e.code === "NO_HEARTS") {
        setPhase({ kind: "no-hearts" });
        return;
      }
      setPhase({
        kind: "error",
        message: e instanceof Error ? e.message : "Не удалось завершить урок",
      });
    }
  }, [lessonId]);

  const gradeAnswer = useCallback(
    async (stepIndex: number, step: StepOut, answer: GradeAnswer) => {
      setPhase({ kind: "grading", stepIndex });
      try {
        const res = await apiFetch<GradeStepResponse>(`/steps/${step.id}/grade`, {
          method: "POST",
          body: JSON.stringify({ answer }),
        });
        setHeartsRemaining(res.hearts_remaining);
        setPhase({ kind: "result", stepIndex, grade: res });
      } catch (e) {
        if (e instanceof ApiError && e.status === 403 && e.code === "NO_HEARTS") {
          setPhase({ kind: "no-hearts" });
          return;
        }
        setPhase({
          kind: "error",
          message: e instanceof Error ? e.message : "Не удалось проверить ответ",
        });
      }
    },
    [],
  );

  // Submit the current step's answer. Called by the CTA or auto-submit step.
  const submitStep = useCallback(
    (stepIndex: number) => {
      if (!start) return;
      const step = start.steps[stepIndex];
      if (!step) return;
      const ans = answers[stepIndex] ?? defaultAnswerFor(step);
      const payload = buildAnswer(step, ans);
      if (payload === null) return;
      void gradeAnswer(stepIndex, step, payload);
    },
    [start, answers, gradeAnswer],
  );

  const advanceFromResult = useCallback(() => {
    if (phase.kind !== "result" || !start) return;
    const nextIndex = phase.stepIndex + 1;
    if (nextIndex >= start.steps.length) {
      void completeLesson();
    } else {
      setPhase({ kind: "step", stepIndex: nextIndex });
    }
  }, [phase, start, completeLesson]);

  // Per-step "update my answer" setters (memoised by current step index).
  const stepIndex = phaseStepIndex(phase);
  const updateAnswer = useCallback(
    (patch: Partial<AnswerState>) => {
      if (stepIndex === null) return;
      setAnswers((prev) => ({
        ...prev,
        [stepIndex]: { ...(prev[stepIndex] ?? {}), ...patch },
      }));
    },
    [stepIndex],
  );

  /* ----------------------------- Render ------------------------------- */

  if (phase.kind === "boot" || phase.kind === "completing") {
    return (
      <Screen title="Урок">
        <Loading
          label={phase.kind === "completing" ? "Завершаем урок..." : "Загружаем урок..."}
        />
      </Screen>
    );
  }

  if (phase.kind === "no-hearts") {
    return <NoHeartsOverlay onBack={() => navigate("/tree")} />;
  }

  if (phase.kind === "error") {
    return (
      <Screen title="Урок">
        <ErrorBox
          message={phase.message}
          onRetry={() => navigate("/tree")}
        />
      </Screen>
    );
  }

  if (phase.kind === "summary") {
    return (
      <Screen title="Урок завершён">
        <Summary
          result={phase.result}
          lessonId={lessonId}
          lessonTitle={`Урок #${lessonId}`}
        />
      </Screen>
    );
  }

  // Active step (step | grading | result).
  if (!start) return null;
  const activeIndex = phaseStepIndex(phase) ?? 0;
  const step = start.steps[activeIndex];
  if (!step) {
    return (
      <Screen title="Урок">
        <ErrorBox message="Шаг не найден" onRetry={() => navigate("/tree")} />
      </Screen>
    );
  }
  const ans = answers[activeIndex] ?? defaultAnswerFor(step);
  const { ctaEnabled, ctaLabel, hideCta } = computeCta(step, ans, ctaArmed, phase);

  const onCta = (): void => {
    if (phase.kind === "result") {
      advanceFromResult();
    } else if (phase.kind === "step") {
      submitStep(activeIndex);
    }
  };

  const stepBody = renderStepBody({
    step,
    answer: ans,
    locked: phase.kind !== "step",
    onUpdate: updateAnswer,
    onAutoSubmit: (answer: GradeAnswer) => {
      // Auto-submit step types: multiple_choice, fill_blank, match_pairs.
      if (phase.kind !== "step") return;
      void gradeAnswer(activeIndex, step, answer);
    },
  });

  return (
    <Screen title={`Шаг ${activeIndex + 1} / ${start.steps.length}`}>
      {showResumeToast && <ResumeToast />}
      <StepCard
        stepIndex={activeIndex}
        totalSteps={start.steps.length}
        heartsRemaining={heartsRemaining}
        ctaLabel={ctaLabel}
        ctaEnabled={ctaEnabled}
        hideCta={hideCta}
        onCta={onCta}
      >
        {stepBody}
      </StepCard>

      {phase.kind === "result" && (
        <GradeOverlay
          grade={phase.grade}
          onNext={advanceFromResult}
          isLast={activeIndex + 1 >= start.steps.length}
        />
      )}
    </Screen>
  );
}

/* ============================ Helpers / atoms =========================== */

function phaseStepIndex(phase: Phase): number | null {
  if (phase.kind === "step" || phase.kind === "grading" || phase.kind === "result") {
    return phase.stepIndex;
  }
  return null;
}

/** Decide whether the CTA is shown, enabled, and what its label says. */
function computeCta(
  step: StepOut,
  ans: AnswerState,
  ctaArmed: boolean,
  phase: Phase,
): { ctaEnabled: boolean; ctaLabel: string; hideCta: boolean } {
  // While the result overlay is up, the overlay has its own CTA — hide the
  // step's CTA to avoid two stacked buttons.
  if (phase.kind === "result") {
    return { ctaEnabled: false, ctaLabel: "Дальше", hideCta: true };
  }

  // Auto-submit step types never expose a CTA.
  if (isAutoSubmitType(step.step_type)) {
    return { ctaEnabled: false, ctaLabel: "—", hideCta: true };
  }

  if (phase.kind === "grading") {
    return { ctaEnabled: false, ctaLabel: "Проверяем...", hideCta: false };
  }

  if (step.step_type === "vocab_intro") {
    return { ctaEnabled: ctaArmed, ctaLabel: "Дальше", hideCta: false };
  }
  if (step.step_type === "translate_en_ru") {
    return {
      ctaEnabled: ctaArmed && (ans.text ?? "").trim().length > 0,
      ctaLabel: "Проверить",
      hideCta: false,
    };
  }
  if (step.step_type === "listen_type") {
    return {
      ctaEnabled: ctaArmed && (ans.text ?? "").trim().length > 0,
      ctaLabel: "Проверить",
      hideCta: false,
    };
  }
  if (step.step_type === "translate_ru_en") {
    return {
      ctaEnabled: ctaArmed && (ans.bank ?? []).length === 0 && (ans.assembled ?? []).length > 0,
      ctaLabel: "Проверить",
      hideCta: false,
    };
  }
  return { ctaEnabled: false, ctaLabel: "Дальше", hideCta: true };
}

function isAutoSubmitType(t: StepType): boolean {
  return t === "multiple_choice" || t === "fill_blank" || t === "match_pairs";
}

/** Build the server-ready answer envelope from the per-step state. */
function buildAnswer(step: StepOut, ans: AnswerState): GradeAnswer | null {
  switch (step.step_type) {
    case "vocab_intro":
      return "";
    case "translate_en_ru":
    case "translate_ru_en":
    case "listen_type":
      if (step.step_type === "translate_ru_en") {
        return (ans.assembled ?? []).join(" ");
      }
      return (ans.text ?? "").trim();
    case "multiple_choice":
      return ans.selectedIndex !== null && ans.selectedIndex !== undefined
        ? String(ans.selectedIndex)
        : null;
    case "fill_blank":
      return ans.selectedOption ?? null;
    case "match_pairs":
      return ans.pairs ?? [];
    default:
      return null;
  }
}

interface BodyArgs {
  step: StepOut;
  answer: AnswerState;
  locked: boolean;
  onUpdate: (patch: Partial<AnswerState>) => void;
  onAutoSubmit: (answer: GradeAnswer) => void;
}

function renderStepBody({ step, answer, locked, onUpdate, onAutoSubmit }: BodyArgs) {
  const payload = step.payload_json as Record<string, unknown>;
  switch (step.step_type) {
    case "vocab_intro":
      return <VocabIntro payload={payload} />;
    case "translate_en_ru":
      return (
        <TranslateEnRu
          payload={payload}
          value={answer.text ?? ""}
          onChange={(text) => onUpdate({ text })}
        />
      );
    case "translate_ru_en":
      return (
        <TranslateRuEn
          payload={payload}
          assembled={answer.assembled ?? []}
          bank={answer.bank ?? []}
          onAssembledChange={(assembled) => onUpdate({ assembled })}
          onBankChange={(bank) => onUpdate({ bank })}
        />
      );
    case "listen_type":
      return (
        <ListenType
          payload={payload}
          value={answer.text ?? ""}
          onChange={(text) => onUpdate({ text })}
        />
      );
    case "multiple_choice":
      return (
        <MultipleChoice
          payload={payload}
          selectedIndex={answer.selectedIndex ?? null}
          locked={locked}
          onPick={(idx) => {
            onUpdate({ selectedIndex: idx });
            onAutoSubmit(String(idx));
          }}
        />
      );
    case "fill_blank":
      return (
        <FillBlank
          payload={payload}
          selectedOption={answer.selectedOption ?? null}
          locked={locked}
          onPick={(opt) => {
            onUpdate({ selectedOption: opt });
            onAutoSubmit(opt);
          }}
        />
      );
    case "match_pairs":
      return (
        <MatchPairs
          payload={payload}
          locked={locked}
          onComplete={(pairs) => {
            onUpdate({ pairs });
            onAutoSubmit(pairs);
          }}
        />
      );
    default:
      return (
        <div className="p-4 text-sm text-slate-500">
          Неизвестный тип шага: <code>{step.step_type}</code>
        </div>
      );
  }
}

/* -------------------------- Overlays / toasts --------------------------- */

function ResumeToast() {
  return (
    <div
      role="status"
      className="pointer-events-none fixed left-1/2 top-4 z-30 -translate-x-1/2 rounded-full bg-slate-900/90 px-4 py-2 text-xs font-semibold text-white shadow-card"
      style={{ animation: "lingomy-toast-fade 1.5s ease-in-out forwards" }}
    >
      <style>{`
        @keyframes lingomy-toast-fade {
          0% { opacity: 0; transform: translate(-50%, -8px); }
          15%, 70% { opacity: 1; transform: translate(-50%, 0); }
          100% { opacity: 0; transform: translate(-50%, -4px); }
        }
      `}</style>
      Продолжаем урок
    </div>
  );
}

function GradeOverlay({
  grade,
  onNext,
  isLast,
}: {
  grade: GradeStepResponse;
  onNext: () => void;
  isLast: boolean;
}) {
  const correct = grade.is_correct;
  return (
    <div
      role="dialog"
      aria-live="polite"
      className="fixed inset-x-0 bottom-0 z-20 px-4 pb-4"
      style={{ paddingBottom: "calc(var(--tg-safe-area-bottom) + 1rem)" }}
    >
      <style>{`
        @keyframes lingomy-grade-up {
          0% { transform: translateY(110%); opacity: 0; }
          100% { transform: translateY(0); opacity: 1; }
        }
        .lingomy-grade-panel { animation: lingomy-grade-up 220ms ease-out; }
      `}</style>
      <div
        className={`lingomy-grade-panel rounded-2xl p-4 shadow-card ${
          correct ? "bg-emerald-100" : "bg-red-100"
        }`}
        data-testid={correct ? "grade-correct" : "grade-wrong"}
      >
        <div className="flex items-center gap-3">
          <div
            className={`flex h-10 w-10 items-center justify-center rounded-full ${
              correct ? "bg-emerald-500 text-white" : "bg-red-500 text-white"
            }`}
            aria-hidden="true"
          >
            {correct ? <CheckIcon className="h-5 w-5" /> : <XIcon className="h-5 w-5" />}
          </div>
          <div className="flex-1">
            <p className={`text-sm font-bold ${correct ? "text-emerald-900" : "text-red-900"}`}>
              {correct ? "Верно!" : "Неверно"}
            </p>
            {correct ? (
              <p className="text-xs font-semibold text-emerald-800">+{grade.xp_step} XP</p>
            ) : (
              grade.correct_value && (
                <p className="text-xs font-medium text-red-900">
                  Правильно: <span className="font-bold">{grade.correct_value}</span>
                </p>
              )
            )}
          </div>
        </div>
        <Button
          size="lg"
          className={`mt-3 w-full ${correct ? "" : "bg-red-500 hover:bg-red-600"}`}
          onClick={onNext}
          data-testid="grade-next"
        >
          {isLast ? "Завершить" : "Дальше"}
        </Button>
      </div>
    </div>
  );
}

function NoHeartsOverlay({ onBack }: { onBack: () => void }) {
  return (
    <Screen>
      <div className="flex h-full flex-col items-center justify-center gap-4 px-6 text-center">
        <div className="text-6xl">💔</div>
        <h2 className="text-xl font-bold text-slate-900">Сердечки закончились</h2>
        <p className="max-w-xs text-sm text-slate-600">
          Подожди, пока они восстановятся, или продолжай в другом уроке позже.
        </p>
        <Button size="lg" className="mt-2" onClick={onBack}>
          Назад на карту
        </Button>
      </div>
    </Screen>
  );
}

function CheckIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="3"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <polyline points="20 6 9 17 4 12" />
    </svg>
  );
}

function XIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="3"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <line x1="18" y1="6" x2="6" y2="18" />
      <line x1="6" y1="6" x2="18" y2="18" />
    </svg>
  );
}
