import { playAudio } from "../audio";

interface Payload {
  audio_filename?: string;
  lemma?: string;
}

interface Props {
  payload: Payload;
  value: string;
  onChange: (v: string) => void;
}

function SpeakerIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
      <path d="M15.54 8.46a5 5 0 0 1 0 7.07" />
      <path d="M19.07 4.93a10 10 0 0 1 0 14.14" />
    </svg>
  );
}

/** Audio dictation — play the word, type what you hear. */
export function ListenType({ payload, value, onChange }: Props) {
  const audioFilename = payload.audio_filename;
  const onListen = (): void => {
    if (audioFilename) void playAudio(audioFilename);
  };

  return (
    <div className="flex flex-col items-center gap-5 pt-4">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Послушай и напечатай
      </p>
      <button
        type="button"
        onClick={onListen}
        disabled={!audioFilename}
        aria-label="Послушать"
        className="flex h-24 w-24 items-center justify-center rounded-full bg-terracotta text-white shadow-card active:scale-95 disabled:opacity-50"
      >
        <SpeakerIcon className="h-10 w-10" />
      </button>
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder="Что ты услышал?"
        autoComplete="off"
        autoCorrect="off"
        autoCapitalize="off"
        spellCheck={false}
        className="w-full rounded-2xl border border-slate-200 bg-white px-4 py-3 text-center text-base text-slate-900 shadow-card outline-none focus:border-terracotta"
      />
    </div>
  );
}
