import { forwardRef } from "react";

export type Band = "promo" | "stable" | "demo";

interface LeaderboardRowProps {
  rank: number;
  userId: number;
  username: string | null;
  weeklyXp: number;
  band: Band;
  isViewer: boolean;
}

/**
 * Fallback display name when the API hands us a null username: use the last
 * four digits of the telegram id so two players in the same league won't
 * collide visually (the full id leaks too much information).
 */
function displayName(username: string | null, userId: number): string {
  if (username && username.trim().length > 0) {
    return username;
  }
  const tail = String(userId).slice(-4).padStart(4, "0");
  return `Игрок #${tail}`;
}

const BAND_ROW_CLS: Record<Band, string> = {
  // Promotion zone: faint terracotta tint
  promo: "bg-terracotta-50/60",
  // Stable zone: plain surface, no tint
  stable: "bg-white",
  // Demotion zone: cool slate-red tint
  demo: "bg-[#C73762]/8",
};

const RANK_TEXT_CLS: Record<Band, string> = {
  promo: "text-terracotta-700",
  stable: "text-slate-700",
  demo: "text-[#C73762]",
};

export const LeaderboardRow = forwardRef<HTMLDivElement, LeaderboardRowProps>(
  function LeaderboardRow(
    { rank, userId, username, weeklyXp, band, isViewer },
    ref,
  ) {
    const viewerCls = isViewer
      ? "ring-2 ring-terracotta ring-offset-1 ring-offset-cream-200 transition-shadow"
      : "";
    return (
      <div
        ref={ref}
        data-band={band}
        data-viewer={isViewer ? "true" : undefined}
        className={`flex items-center gap-3 rounded-xl px-3 py-2.5 ${BAND_ROW_CLS[band]} ${viewerCls}`}
      >
        <span
          className={`w-7 shrink-0 text-center text-lg font-bold tabular-nums ${RANK_TEXT_CLS[band]}`}
        >
          {rank}
        </span>
        <span className="flex-1 truncate text-sm font-medium text-slate-900">
          {displayName(username, userId)}
          {isViewer && (
            <span className="ml-2 align-middle text-[10px] font-semibold uppercase tracking-wide text-terracotta">
              ты
            </span>
          )}
        </span>
        <span className="shrink-0 text-sm font-semibold tabular-nums text-slate-900">
          {weeklyXp}
          <span className="ml-1 text-xs font-medium text-slate-500">XP</span>
        </span>
      </div>
    );
  },
);
