import { useState } from "react";

import { Screen } from "@/components/Screen";

import { FriendsList } from "./friends/FriendsList";
import { PendingList } from "./friends/PendingList";
import { FriendsLeaderboard } from "./friends/FriendsLeaderboard";
import { InviteCta } from "./friends/InviteCta";

type TabKey = "friends" | "pending" | "leaderboard";

const TABS: { key: TabKey; label: string }[] = [
  { key: "friends", label: "Друзья" },
  { key: "pending", label: "Запросы" },
  { key: "leaderboard", label: "Топ друзей" },
];

export function Friends() {
  const [tab, setTab] = useState<TabKey>("friends");

  return (
    <Screen title="Друзья">
      <div className="flex h-full flex-col">
        {/* Hand-rolled tab bar — no headless lib. */}
        <div
          role="tablist"
          aria-label="Разделы друзей"
          className="mb-3 flex items-center gap-1 rounded-full bg-white p-1 shadow-card"
        >
          {TABS.map((t) => {
            const active = tab === t.key;
            return (
              <button
                key={t.key}
                role="tab"
                aria-selected={active}
                onClick={() => setTab(t.key)}
                className={`flex-1 rounded-full px-3 py-2 text-xs font-semibold transition-colors ${
                  active
                    ? "bg-terracotta text-white shadow-sm"
                    : "text-slate-600 hover:text-slate-900"
                }`}
              >
                {t.label}
              </button>
            );
          })}
        </div>

        <div className="flex-1">
          {tab === "friends" && <FriendsList />}
          {tab === "pending" && <PendingList />}
          {tab === "leaderboard" && <FriendsLeaderboard />}
        </div>

        <InviteCta />
      </div>
    </Screen>
  );
}
