import { useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import { apiFetch } from "@/lib/api";
import { Card } from "@/components/Card";
import { Loading } from "@/components/Loading";
import { ErrorBox } from "@/components/ErrorBox";

import type { FriendshipOut } from "./types";
import { avatarLetter, displayName, formatRuDate, sortFriends } from "./util";

interface FriendsListProps {
  /** Rendered when the list is empty — keeps the invite CTA wording in one place. */
  emptyHint?: React.ReactNode;
}

export function FriendsList({ emptyHint }: FriendsListProps) {
  const qc = useQueryClient();
  const q = useQuery<FriendshipOut[]>({
    queryKey: ["friends", "accepted"],
    queryFn: () => apiFetch<FriendshipOut[]>("/friends?status=accepted"),
  });

  const removeMut = useMutation({
    mutationFn: (id: number) => apiFetch<void>(`/friends/${id}`, { method: "DELETE" }),
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["friends", "accepted"] });
      void qc.invalidateQueries({ queryKey: ["friends", "leaderboard"] });
    },
  });

  if (q.isLoading) return <Loading label="Загрузка друзей..." />;
  if (q.error || !q.data) {
    return (
      <ErrorBox
        message={(q.error as Error)?.message ?? "Не удалось загрузить список друзей"}
        onRetry={() => void q.refetch()}
      />
    );
  }

  const rows = sortFriends(q.data);
  if (rows.length === 0) {
    return (
      <Card padding="lg" className="flex flex-col items-center gap-2 text-center">
        <p className="text-sm text-slate-600">Пока нет друзей. Поделись приглашением.</p>
        {emptyHint}
      </Card>
    );
  }

  return (
    <ul className="flex flex-col gap-2">
      {rows.map((fs) => (
        <FriendRow
          key={fs.id}
          row={fs}
          onRemove={() => removeMut.mutate(fs.id)}
          removing={removeMut.isPending && removeMut.variables === fs.id}
        />
      ))}
    </ul>
  );
}

function FriendRow({
  row,
  onRemove,
  removing,
}: {
  row: FriendshipOut;
  onRemove: () => void;
  removing: boolean;
}) {
  const [menuOpen, setMenuOpen] = useState(false);
  const name = displayName(row.username, row.friend_id);
  const since = formatRuDate(row.accepted_at ?? row.created_at);

  return (
    <li>
      <Card padding="md" className="flex items-center gap-3">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-terracotta text-base font-bold text-white">
          {avatarLetter(row.username, row.friend_id)}
        </div>
        <div className="flex min-w-0 flex-1 flex-col">
          <span className="truncate text-sm font-semibold text-slate-900">{name}</span>
          <span className="text-xs text-slate-500">Друг с {since}</span>
        </div>
        <div className="relative">
          <button
            type="button"
            aria-label="Меню"
            onClick={() => setMenuOpen((v) => !v)}
            className="flex h-8 w-8 items-center justify-center rounded-full text-lg text-slate-600 hover:bg-cream-300/40"
          >
            ⋯
          </button>
          {menuOpen && (
            <>
              {/* invisible backdrop to close on outside-click */}
              <button
                type="button"
                aria-hidden
                tabIndex={-1}
                className="fixed inset-0 z-10 cursor-default bg-transparent"
                onClick={() => setMenuOpen(false)}
              />
              <div className="absolute right-0 top-full z-20 mt-1 w-44 overflow-hidden rounded-xl bg-white shadow-card">
                <button
                  type="button"
                  disabled={removing}
                  onClick={() => {
                    setMenuOpen(false);
                    onRemove();
                  }}
                  className="block w-full px-4 py-2.5 text-left text-sm text-slate-900 hover:bg-cream-200 disabled:opacity-50"
                >
                  Удалить из друзей
                </button>
              </div>
            </>
          )}
        </div>
      </Card>
    </li>
  );
}
