/* --------------------------- Wire-shape types ---------------------------- */

interface LeagueOut {
  id: number;
  tier: string;
  sort_order: number;
}
interface LeagueSeasonOut {
  id: number;
  league_id: number;
  season_start: string; // ISO YYYY-MM-DD
  season_end: string;
  is_active: boolean;
}
interface MyLeagueResponse {
  league: LeagueOut;
  season: LeagueSeasonOut;
  my_rank: number;
  my_weekly_xp: number;
  member_count: number;
}
interface LeaderboardRowOut {
  rank: number;
  user_id: number;
  username: string | null;
  weekly_xp: number;
}
interface LeaderboardResponse {
  rows: LeaderboardRowOut[];
  viewer_rank: number | null;
  viewer_xp: number | null;
  total: number;
}

/* ---------------------------- Date helpers ------------------------------- */

/**
 * Parse an ISO date string ("YYYY-MM-DD") as a *local* date at 00:00 so we
 * don't get bitten by timezone shifts. Returns null on bad input rather than
 * throwing — the date is then simply hidden.
 */
function parseIsoDate(s: string): Date | null {
  const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
  if (!m) return null;
  const y = Number(m[1]);
  const mo = Number(m[2]);
  const d = Number(m[3]);
  if (!Number.isFinite(y) || !Number.isFinite(mo) || !Number.isFinite(d)) return null;
  return new Date(y, mo - 1, d);
}

function formatDM(d: Date): string {
  const day = String(d.getDate()).padStart(2, "0");
  return `${day}.${String(d.getMonth() + 1).padStart(2, "0")}`;
}

/**
 * Days remaining until the season end date (inclusive of the end day). Uses
 * local-day arithmetic so "tomorrow" is always 1 regardless of the current
 * hour. Returns 0 if the season has already ended.
 */
function daysRemaining(seasonEndIso: string, now: Date = new Date()): number {
  const end = parseIsoDate(seasonEndIso);
  if (!end) return 0;
  // Snap "now" to local midnight so we count whole days.
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const ms = end.getTime() - today.getTime();
  if (ms <= 0) return 0;
  return Math.ceil(ms / (24 * 60 * 60 * 1000));
}

function pluralizeDaysRu(n: number): string {
  const abs = Math.abs(n) % 100;
  const last = abs % 10;
  if (abs >= 11 && abs <= 14) return "дней";
  if (last === 1) return "день";
  if (last >= 2 && last <= 4) return "дня";
  return "дней";
}

/* ------------------------------- Bands ----------------------------------- */

/**
 * Three-band layout for a 50-row leaderboard.
 *   ranks 1-15  → "promo"   (terracotta tint, "Зона повышения")
 *   ranks 16-35 → "stable"
 *   ranks 36-50 → "demo"    (slate-red tint, "Зона понижения")
 *
 * For sparse leagues (member_count < 50) the bands are still computed on the
 * full schedule so a player at rank 14 in a 17-person league still sees
 * themselves in the promotion band — which is correct for the rollover algo.
 */
function bandForRank(rank: number): Band {
  if (rank <= 15) return "promo";
  if (rank <= 35) return "stable";
  return "demo";
}

interface BandSpec {
  band: Band;
  caption: string;
  rows: LeaderboardRowOut[];
}

function splitIntoBands(rows: LeaderboardRowOut[]): BandSpec[] {
  const groups: Record<Band, LeaderboardRowOut[]> = {
    promo: [],
    stable: [],
    demo: [],
  };
  for (const r of rows) {
    groups[bandForRank(r.rank)].push(r);
  }
  return [
    { band: "promo", caption: "Зона повышения", rows: groups.promo },
    { band: "stable", caption: "Стабильная зона", rows: groups.stable },
    { band: "demo", caption: "Зона понижения", rows: groups.demo },
  ];
}

/* --------------------------------- UI ------------------------------------ */

interface HeaderProps {
  tierSlug: string;
  season: LeagueSeasonOut;
  memberCount: number;
}

function LeagueHeader({ tierSlug, season, memberCount }: HeaderProps) {
  const meta = getTierMeta(tierSlug);
  const start = parseIsoDate(season.season_start);
  const end = parseIsoDate(season.season_end);
  const days = daysRemaining(season.season_end);

  let range = "";
  if (start && end) {
    range = `${formatDM(start)}–${formatDM(end)}`;
  }

  const seasonLabel = (() => {
    if (!start) return null;
    // ISO week number — calmer than spelling out the date range twice.
    const weekNum = getIsoWeekNumber(start);
    return `Неделя ${weekNum}`;
  })();

  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-3">
        <span
          aria-hidden
          className="flex h-12 w-12 items-center justify-center rounded-2xl text-3xl"
          style={{ backgroundColor: `${meta.color}22` }}
        >
          {meta.emoji}
        </span>
        <div className="flex flex-col">
          <span className="text-xs font-semibold uppercase tracking-wide text-slate-500">
            Твоя лига
          </span>
          <span
            className="text-2xl font-bold leading-tight tracking-tight"
            style={{ color: meta.color }}
          >
            {meta.label_ru}
          </span>
        </div>
      </div>
      <p className="text-sm text-slate-600">
        {seasonLabel && <span className="font-medium text-slate-700">{seasonLabel}</span>}
        {seasonLabel && range && <span className="px-1 text-slate-400">·</span>}
        {range && <span>{range}</span>}
        {(seasonLabel || range) && (
          <span className="px-1 text-slate-400">·</span>
        )}
        <span aria-hidden>⏱ </span>
        <span className="text-slate-700">
          осталось {days} {pluralizeDaysRu(days)}
        </span>
      </p>
      {memberCount < 50 && memberCount > 0 && (
        <p className="text-xs text-slate-500">
          В этой лиге пока {memberCount}{" "}
          {pluralizeMembersRu(memberCount)}
        </p>
      )}
    </div>
  );
}

function pluralizeMembersRu(n: number): string {
  const abs = Math.abs(n) % 100;
  const last = abs % 10;
  if (abs >= 11 && abs <= 14) return "игроков";
  if (last === 1) return "игрок";
  if (last >= 2 && last <= 4) return "игрока";
  return "игроков";
}

/** ISO 8601 week number for the given date. */
function getIsoWeekNumber(d: Date): number {
  // Copy and snap to Thursday of the same ISO week.
  const target = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dayNr = (target.getUTCDay() + 6) % 7;
  target.setUTCDate(target.getUTCDate() - dayNr + 3);
  const firstThursday = new Date(Date.UTC(target.getUTCFullYear(), 0, 4));
  const firstDayNr = (firstThursday.getUTCDay() + 6) % 7;
  firstThursday.setUTCDate(firstThursday.getUTCDate() - firstDayNr + 3);
  const diff = target.getTime() - firstThursday.getTime();
  return 1 + Math.round(diff / (7 * 24 * 60 * 60 * 1000));
}

/* ---------------------------- Empty state -------------------------------- */

function NoLeagueState({ onGoToTree }: { onGoToTree: () => void }) {
  return (
    <Screen title="Лига">
      <div className="flex h-full flex-col items-center justify-center gap-4 px-4 text-center">
        <div aria-hidden className="text-5xl">
          {"\u{1F949}"}
        </div>
        <h2 className="text-lg font-semibold text-slate-900">Ты ещё не в лиге</h2>
        <p className="max-w-xs text-sm text-slate-600">
          Закончи один урок, чтобы попасть в Бронзу и начать соревноваться с другими.
        </p>
        <Button onClick={onGoToTree}>К урокам</Button>
      </div>
    </Screen>
  );
}

/* ------------------------------ Screen ----------------------------------- */

export function League() {
  const [, setLocation] = useLocation();

  const meQ = useQuery<MyLeagueResponse, ApiError>({
    queryKey: ["leagues", "me"],
    queryFn: () => apiFetch<MyLeagueResponse>("/leagues/me"),
    // 404 NO_LEAGUE is a legitimate state, not a retry-worthy error.
    retry: (failureCount, error) => {
      if (error instanceof ApiError && error.status === 404) return false;
      return failureCount < 1;
    },
  });

  const seasonId = meQ.data?.season.id;
  const lbQ = useQuery<LeaderboardResponse, ApiError>({
    queryKey: ["leagues", "leaderboard", seasonId],
    queryFn: () => apiFetch<LeaderboardResponse>(`/leagues/${seasonId}/leaderboard`),
    enabled: typeof seasonId === "number",
  });

  const viewerRowRef = useRef<HTMLDivElement | null>(null);
  const didScrollRef = useRef(false);

  useEffect(() => {
    if (didScrollRef.current) return;
    if (!lbQ.data || !meQ.data) return;
    const node = viewerRowRef.current;
    if (!node) return;
    // One-shot scroll on first successful render.
    didScrollRef.current = true;
    // requestAnimationFrame so layout has settled.
    requestAnimationFrame(() => {
      try {
        node.scrollIntoView({ block: "center", behavior: "smooth" });
      } catch {
        node.scrollIntoView();
      }
    });
  }, [lbQ.data, meQ.data]);

  /* -------- loading / error / empty branches -------- */

  if (meQ.isLoading) {
    return (
      <Screen title="Лига">
        <Loading />
      </Screen>
    );
  }

  if (meQ.error instanceof ApiError && meQ.error.status === 404 && meQ.error.code === "NO_LEAGUE") {
    return <NoLeagueState onGoToTree={() => setLocation("/tree")} />;
  }

  if (meQ.error || !meQ.data) {
    return (
      <Screen title="Лига">
        <ErrorBox
          message={(meQ.error as Error | undefined)?.message ?? "Не удалось загрузить лигу"}
          onRetry={() => {
            void meQ.refetch();
          }}
        />
      </Screen>
    );
  }

  if (lbQ.isLoading) {
    return (
      <Screen title="Лига">
        <Loading />
      </Screen>
    );
  }

  if (lbQ.error || !lbQ.data) {
    return (
      <Screen title="Лига">
        <ErrorBox
          message={(lbQ.error as Error | undefined)?.message ?? "Не удалось загрузить таблицу"}
          onRetry={() => {
            void lbQ.refetch();
          }}
        />
      </Screen>
    );
  }

  /* -------- happy path -------- */

  const my = meQ.data;
  const lb = lbQ.data;
  const viewerRank = lb.viewer_rank ?? my.my_rank;
  // If the viewer's rank is beyond the top-50 rows we still highlight nothing
  // in the list and show a "you-are-here" footer card so they know where they
  // stand. The backend currently caps rows at 50.
  const viewerInList = lb.rows.some((r) => r.rank === viewerRank);

  const bands = splitIntoBands(lb.rows);

  return (
    <Screen title="Лига">
      <div className="flex flex-col gap-4 pb-4">
        <LeagueHeader
          tierSlug={my.league.tier}
          season={my.season}
          memberCount={my.member_count}
        />

        <Card padding="md" className="flex items-center justify-between">
          <div className="flex flex-col">
            <span className="text-xs font-semibold uppercase tracking-wide text-slate-500">
              Ты сейчас
            </span>
            <span className="text-lg font-semibold text-slate-900">
              #{viewerRank}
              <span className="ml-2 text-sm font-normal text-slate-500">
                из {my.member_count}
              </span>
            </span>
          </div>
          <div className="text-right">
            <span className="text-xs font-semibold uppercase tracking-wide text-slate-500">
              Твои XP
            </span>
            <div className="text-lg font-semibold text-terracotta">
              {my.my_weekly_xp}
              <span className="ml-1 text-xs font-medium text-slate-500">XP</span>
            </div>
          </div>
        </Card>

        {bands.map((b) => {
          if (b.rows.length === 0) return null;
          return (
            <section key={b.band} className="flex flex-col gap-2">
              <h3 className="px-1 text-xs font-semibold uppercase tracking-wide text-slate-500">
                {b.caption}
              </h3>
              <Card padding="sm" className="flex flex-col gap-1">
                {b.rows.map((row) => {
                  const isViewer = row.rank === viewerRank;
                  return (
                    <LeaderboardRow
                      key={row.user_id}
                      ref={isViewer ? viewerRowRef : undefined}
                      rank={row.rank}
                      userId={row.user_id}
                      username={row.username}
                      weeklyXp={row.weekly_xp}
                      band={b.band}
                      isViewer={isViewer}
                    />
                  );
                })}
              </Card>
            </section>
          );
        })}

        {!viewerInList && (
          <Card padding="md" className="flex items-center justify-between">
            <span className="text-sm text-slate-600">
              Ты на месте <span className="font-semibold text-slate-900">#{viewerRank}</span>
            </span>
            <span className="text-sm font-semibold text-terracotta">
              {my.my_weekly_xp}
              <span className="ml-1 text-xs font-medium text-slate-500">XP</span>
            </span>
          </Card>
        )}
      </div>
    </Screen>
  );
}
