import type { ReactNode } from "react";

interface ScreenProps {
  title?: string;
  /** Optional right-side adornment (e.g. a settings cog). */
  headerRight?: ReactNode;
  children: ReactNode;
}

/**
 * Page shell that handles iOS safe-area, a brand-styled header, and the
 * page background. Use this for every screen so the chrome is consistent.
 */
export function Screen({ title, headerRight, children }: ScreenProps) {
  return (
    <div
      className="flex h-full flex-col bg-cream-200"
      style={{
        paddingTop: "var(--tg-safe-area-top)",
        paddingBottom: "var(--tg-safe-area-bottom)",
      }}
    >
      {title && (
        <header className="flex items-center justify-between px-5 pb-2 pt-4">
          <h1 className="text-xl font-bold tracking-tight text-slate-900">{title}</h1>
          {headerRight}
        </header>
      )}
      <main className="flex-1 overflow-y-auto px-4 pb-6 pt-2">{children}</main>
    </div>
  );
}
