/**
 * Authentication flow: Telegram initData → JWT exchange + refresh.
 *
 * Tokens are kept in the Zustand `useAuthStore`, which persists them to
 * localStorage (see store/auth.ts). This module is the only place that knows
 * about the wire protocol with /auth/*.
 */

import { apiFetch, ApiError } from "./api";
import { getInitData } from "./twa";
import type { TokenResponse } from "./types";
import { useAuthStore } from "@/store/auth";

/** 60-second safety margin so we refresh before the server actually expires us. */
const EXPIRY_SKEW_SECONDS = 60;

function nowSeconds(): number {
  return Math.floor(Date.now() / 1000);
}

function isExpired(expiresAt: number | null): boolean {
  if (!expiresAt) return true;
  return expiresAt - EXPIRY_SKEW_SECONDS <= nowSeconds();
}

function storeTokens(t: TokenResponse): void {
  useAuthStore.getState().setTokens(t);
}

/**
 * POST /auth/telegram — exchanges current `initData` for a fresh token pair.
 * Throws if initData is missing (caller should handle by showing the
 * "Open in Telegram" hint) or if the server rejects the signature.
 */
export async function login(): Promise<TokenResponse> {
  const initData = getInitData();
  if (!initData) {
    throw new ApiError(0, "NO_INIT_DATA", "Telegram initData unavailable");
  }
  const tokens = await apiFetch<TokenResponse>("/auth/telegram", {
    method: "POST",
    body: JSON.stringify({ init_data: initData }),
    skipAuth: true,
  });
  storeTokens(tokens);
  return tokens;
}

/**
 * POST /auth/refresh — uses the stored refresh token to obtain a new access
 * token pair. Returns the new tokens or `null` if refresh fails (caller
 * should fall back to a fresh login).
 */
export async function refresh(): Promise<TokenResponse | null> {
  const refreshToken = useAuthStore.getState().refreshToken;
  if (!refreshToken) return null;
  try {
    const tokens = await apiFetch<TokenResponse>("/auth/refresh", {
      method: "POST",
      body: JSON.stringify({ refresh_token: refreshToken }),
      skipAuth: true,
    });
    storeTokens(tokens);
    return tokens;
  } catch {
    return null;
  }
}

/**
 * Internal helper used by apiFetch when it sees a 401. Tries refresh, and if
 * that fails, clears tokens.
 */
export async function tryRefresh(): Promise<boolean> {
  const tokens = await refresh();
  if (!tokens) {
    useAuthStore.getState().clear();
    return false;
  }
  return true;
}

export function logout(): void {
  useAuthStore.getState().clear();
}

/**
 * On app boot: restore tokens from persistent storage, refresh if expired,
 * and finally fall back to a fresh `login()`. Returns true if we have a
 * usable access token at the end.
 */
export async function bootstrapAuth(): Promise<boolean> {
  const state = useAuthStore.getState();

  // Have a non-expired access token already → done.
  if (state.accessToken && !isExpired(state.accessExpiresAt)) {
    return true;
  }

  // Try to refresh using the existing refresh token.
  if (state.refreshToken && !isExpired(state.refreshExpiresAt)) {
    const refreshed = await refresh();
    if (refreshed) return true;
  }

  // Last resort: fresh login from initData.
  try {
    await login();
    return true;
  } catch (e) {
    // Surface NO_INIT_DATA distinctly so AuthGate can show the "Open in
    // Telegram" message instead of a generic error.
    throw e;
  }
}
