/**
 * Thin typed wrapper around `window.Telegram.WebApp`.
 *
 * Everything that touches the Telegram SDK lives here. Other modules import
 * helpers from this file so we can mock it cleanly in tests and tolerate
 * running in a plain browser (no SDK injected).
 */

/* eslint-disable @typescript-eslint/no-explicit-any */

export type ColorScheme = "light" | "dark";

export interface TelegramUser {
  id: number;
  first_name?: string;
  last_name?: string;
  username?: string;
  language_code?: string;
  is_premium?: boolean;
  photo_url?: string;
}

export interface TelegramWebApp {
  initData: string;
  initDataUnsafe?: { user?: TelegramUser };
  version: string;
  colorScheme: ColorScheme;
  viewportHeight: number;
  viewportStableHeight: number;
  themeParams?: Record<string, string>;
  ready: () => void;
  expand: () => void;
  close: () => void;
  HapticFeedback?: {
    impactOccurred: (style: "light" | "medium" | "heavy" | "rigid" | "soft") => void;
    notificationOccurred: (type: "error" | "success" | "warning") => void;
    selectionChanged: () => void;
  };
  MainButton?: {
    setText: (text: string) => void;
    show: () => void;
    hide: () => void;
    onClick: (cb: () => void) => void;
    offClick: (cb: () => void) => void;
  };
  BackButton?: {
    show: () => void;
    hide: () => void;
    onClick: (cb: () => void) => void;
    offClick: (cb: () => void) => void;
  };
}

declare global {
  interface Window {
    Telegram?: { WebApp?: TelegramWebApp };
  }
}

/** Lazy accessor — never throws if SDK is not loaded (dev in browser). */
function tg(): TelegramWebApp | undefined {
  return typeof window !== "undefined" ? window.Telegram?.WebApp : undefined;
}

let _initialized = false;

/**
 * Idempotent boot. Safe to call multiple times (e.g. on each module reload
 * during HMR). Calls `ready()` and `expand()` so the WebView fills the screen.
 */
export function initTelegram(): void {
  if (_initialized) return;
  const app = tg();
  if (!app) return;
  try {
    app.ready();
    app.expand();
  } catch (e) {
    // SDK loaded but methods missing on older clients — ignore.
    // eslint-disable-next-line no-console
    console.warn("[twa] init failed:", e);
  }
  _initialized = true;
}

/**
 * Returns the signed initData query string. Falls back to
 * `VITE_DEV_INIT_DATA` if running outside Telegram (local browser dev).
 */
export function getInitData(): string {
  const real = tg()?.initData ?? "";
  if (real) return real;
  const devFallback = (import.meta.env.VITE_DEV_INIT_DATA as string | undefined) ?? "";
  return devFallback;
}

/** Whether we're running inside the actual Telegram client. */
export function isInsideTelegram(): boolean {
  return Boolean(tg()?.initData);
}

export function getColorScheme(): ColorScheme {
  return tg()?.colorScheme ?? "light";
}

export function getViewportHeight(): number {
  return tg()?.viewportHeight ?? (typeof window !== "undefined" ? window.innerHeight : 640);
}

export function impactOccurred(
  style: "light" | "medium" | "heavy" | "rigid" | "soft" = "light",
): void {
  try {
    tg()?.HapticFeedback?.impactOccurred(style);
  } catch {
    /* haptics unavailable */
  }
}

export function notificationOccurred(type: "error" | "success" | "warning"): void {
  try {
    tg()?.HapticFeedback?.notificationOccurred(type);
  } catch {
    /* haptics unavailable */
  }
}

/** Direct accessor for advanced cases (MainButton, BackButton). Prefer wrappers. */
export function getWebApp(): TelegramWebApp | undefined {
  return tg();
}
