import { useEffect, useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";

import { apiFetch } from "@/lib/api";
import { getCompleted, subscribe } from "@/lib/treeCompleted";
import { Card } from "@/components/Card";
import { Screen } from "@/components/Screen";
import { Loading } from "@/components/Loading";
import { ErrorBox } from "@/components/ErrorBox";

/* ----------------------------- DTOs (local) ------------------------------ */
// Mirrors `app/api/schemas/courses.py`. Kept local to the Tree screen so the
// shared `lib/types.ts` stays minimal until other screens need these too;
// promote to lib/types.ts when Lesson/League/Friends start consuming courses.

interface LessonOut {
  id: number;
  unit_id: number;
  sort_order: number;
  title: string;
  xp_reward: number;
  required_to_unlock_next: boolean;
}

interface UnitOut {
  id: number;
  course_id: number;
  sort_order: number;
  title: string;
  cefr_level: string;
  icon_emoji: string | null;
  description: string | null;
  lessons: LessonOut[];
}

interface CourseOut {
  id: number;
  code: string;
  title: string;
  description: string | null;
  target_lang: string;
  source_lang: string;
  sort_order: number;
  units: UnitOut[];
}

/* ------------------------------ Helpers ---------------------------------- */

type LessonState = "completed" | "available" | "locked";

/**
 * Walks every (unit, lesson) in display order and returns a map of
 * `lessonId → state`. A lesson is "available" iff it is the first lesson in
 * the course or the previous lesson is in `completed`. Earlier-completed
 * lessons remain "completed" even if later ones are too.
 */
function computeLessonStates(
  units: UnitOut[],
  completed: Set<number>,
): Map<number, LessonState> {
  const result = new Map<number, LessonState>();
  const sortedUnits = [...units].sort(
    (a, b) => a.sort_order - b.sort_order || a.id - b.id,
  );
  let unlockNext = true; // first lesson of the course is always unlocked
  for (const unit of sortedUnits) {
    const sortedLessons = [...unit.lessons].sort(
      (a, b) => a.sort_order - b.sort_order || a.id - b.id,
    );
    for (const lesson of sortedLessons) {
      if (completed.has(lesson.id)) {
        result.set(lesson.id, "completed");
        unlockNext = true;
      } else if (unlockNext) {
        result.set(lesson.id, "available");
        unlockNext = false;
      } else {
        result.set(lesson.id, "locked");
      }
    }
  }
  return result;
}

/* ------------------------------ Atoms ------------------------------------ */

function CheckIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="3"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <polyline points="20 6 9 17 4 12" />
    </svg>
  );
}

function LockIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <rect x="4" y="11" width="16" height="10" rx="2" />
      <path d="M8 11V7a4 4 0 0 1 8 0v4" />
    </svg>
  );
}

interface LessonNodeProps {
  lesson: LessonOut;
  state: LessonState;
  /** Horizontal offset for the snake-path layout, in px. */
  offset: number;
  onTap: (lessonId: number) => void;
}

function LessonNode({ lesson, state, offset, onTap }: LessonNodeProps) {
  const isLocked = state === "locked";
  const stateLabel =
    state === "completed" ? "пройден" : state === "available" ? "доступен" : "заблокирован";

  const buttonCls =
    state === "completed"
      ? "bg-terracotta text-white shadow-card"
      : state === "available"
        ? "bg-white text-slate-900 border-2 border-terracotta animate-tree-pulse"
        : "bg-slate-300 text-slate-500 opacity-50";

  // Hit target is always >= 44x44 by wrapping a 64px circle with min-h-11.
  return (
    <div
      className="flex w-full flex-col items-center"
      style={{ transform: `translateX(${offset}px)` }}
    >
      <button
        type="button"
        data-testid={`lesson-${lesson.id}`}
        data-state={state}
        disabled={isLocked}
        aria-label={`${lesson.title} — ${stateLabel}`}
        onClick={() => !isLocked && onTap(lesson.id)}
        className={`flex h-16 w-16 items-center justify-center rounded-full font-bold transition-transform active:scale-95 disabled:cursor-not-allowed disabled:active:scale-100 ${buttonCls}`}
      >
        {state === "completed" && <CheckIcon className="h-7 w-7" />}
        {state === "locked" && <LockIcon className="h-6 w-6" />}
        {state === "available" && <span className="text-base">{lesson.sort_order}</span>}
      </button>
      <span
        className={`mt-1.5 max-w-[120px] truncate text-center text-xs ${
          isLocked ? "text-slate-400" : "text-slate-600"
        }`}
      >
        {lesson.title}
      </span>
    </div>
  );
}

interface UnitSectionProps {
  unit: UnitOut;
  states: Map<number, LessonState>;
  onTap: (lessonId: number) => void;
}

function UnitSection({ unit, states, onTap }: UnitSectionProps) {
  const sortedLessons = useMemo(
    () => [...unit.lessons].sort((a, b) => a.sort_order - b.sort_order || a.id - b.id),
    [unit.lessons],
  );

  // Snake path: alternate offsets (-40, -20, 0, 20, 40) cycling. Tweak the
  // amplitude so it stays comfortable on 360px-wide screens.
  const offsets = [-48, -16, 16, 48, 16, -16];

  return (
    <section className="flex flex-col gap-4">
      <Card padding="md" className="flex flex-col gap-1.5">
        <div className="flex items-center gap-2">
          {unit.icon_emoji && (
            <span className="text-2xl leading-none" aria-hidden="true">
              {unit.icon_emoji}
            </span>
          )}
          <h2 className="flex-1 text-base font-semibold text-slate-900">{unit.title}</h2>
          <span className="lg-pill bg-cream-300 text-slate-700">{unit.cefr_level}</span>
        </div>
        {unit.description && (
          <p className="text-sm text-slate-600">{unit.description}</p>
        )}
      </Card>

      <div
        className="flex flex-col items-center gap-5 py-2"
        data-testid={`unit-${unit.id}`}
      >
        {sortedLessons.map((lesson, idx) => (
          <LessonNode
            key={lesson.id}
            lesson={lesson}
            state={states.get(lesson.id) ?? "locked"}
            offset={offsets[idx % offsets.length]}
            onTap={onTap}
          />
        ))}
      </div>
    </section>
  );
}

/* ----------------------------- Screen ------------------------------------ */

/**
 * Tree — Duolingo-style course tree.
 *
 * Renders the first available course's units as a vertical list, with each
 * unit's lessons laid out on a snake-path of 64×64 circular nodes.
 *
 * Completion state is read from localStorage via
 * `@/lib/treeCompleted` (see that module for the migration path to a real
 * `/me`-backed completed-lessons field). The Lesson screen writes to that
 * helper when a lesson is finished. This component re-reads on mount and on
 * every `visibilitychange`, so when the user comes back from the Lesson
 * screen the new state is reflected immediately.
 *
 * Unlock rule: the first lesson of the course is always available, every
 * other lesson is "available" iff the lesson immediately before it (by
 * `(unit.sort_order, lesson.sort_order)`) is in the completed set.
 */
export function Tree() {
  const [, navigate] = useLocation();
  const [completed, setCompleted] = useState<Set<number>>(() => getCompleted());

  // Refresh completed-set on mount + whenever the tab becomes visible again
  // (likely after finishing a lesson). Storage events cover multi-tab cases.
  useEffect(() => {
    const unsubscribe = subscribe(() => setCompleted(getCompleted()));
    return unsubscribe;
  }, []);

  const coursesQ = useQuery<CourseOut[]>({
    queryKey: ["courses"],
    queryFn: () => apiFetch<CourseOut[]>("/courses"),
  });

  if (coursesQ.isLoading) {
    return (
      <Screen title="Дерево уроков">
        <Loading />
      </Screen>
    );
  }

  if (coursesQ.error || !coursesQ.data) {
    return (
      <Screen title="Дерево уроков">
        <ErrorBox
          message={
            (coursesQ.error as Error | undefined)?.message ?? "Не удалось загрузить курс"
          }
          onRetry={() => {
            void coursesQ.refetch();
          }}
        />
      </Screen>
    );
  }

  const course = coursesQ.data[0];
  if (!course) {
    return (
      <Screen title="Дерево уроков">
        <ErrorBox
          message="Курсы пока не загружены. Загляни позже."
          onRetry={() => {
            void coursesQ.refetch();
          }}
        />
      </Screen>
    );
  }

  const states = computeLessonStates(course.units, completed);
  const sortedUnits = [...course.units].sort(
    (a, b) => a.sort_order - b.sort_order || a.id - b.id,
  );

  const onTapLesson = (lessonId: number): void => {
    navigate(`/lessons/${lessonId}`);
  };

  return (
    <Screen title={course.title}>
      {/* Local keyframes — kept inline to avoid coordinating with parallel
          agents over tailwind.config.ts / index.css. Pure CSS, no JS timer. */}
      <style>{`
        @keyframes lingomy-tree-pulse {
          0%, 100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(224, 120, 86, 0.45); }
          50% { transform: scale(1.04); box-shadow: 0 0 0 8px rgba(224, 120, 86, 0); }
        }
        .animate-tree-pulse { animation: lingomy-tree-pulse 1.8s ease-in-out infinite; }
        @media (prefers-reduced-motion: reduce) {
          .animate-tree-pulse { animation: none; }
        }
      `}</style>
      <div className="flex flex-col gap-6">
        {course.description && (
          <p className="-mt-1 px-1 text-sm text-slate-600">{course.description}</p>
        )}

        {sortedUnits.length === 0 ? (
          <Card padding="md">
            <p className="text-sm text-slate-600">
              В этом курсе ещё нет юнитов. Контент скоро появится.
            </p>
          </Card>
        ) : (
          sortedUnits.map((unit) => (
            <UnitSection key={unit.id} unit={unit} states={states} onTap={onTapLesson} />
          ))
        )}
      </div>
    </Screen>
  );
}
