import { useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";

import { apiFetch } from "@/lib/api";
import type { HeartsResponse } from "@/lib/types";
import { Button } from "@/components/Button";
import { Card } from "@/components/Card";

import type { CompleteLessonResponse } from "./types";

interface Props {
  result: CompleteLessonResponse;
  lessonId: number;
  lessonTitle: string;
}

/**
 * End-of-lesson summary. Awards screen + "back to course tree" CTA.
 *
 * On mount we:
 *   1. Mark the lesson as completed in the local "tree completed" store —
 *      wrapped in dynamic import + try/catch so a missing helper module
 *      never blanks out the screen.
 *   2. Re-fetch /hearts to display the max — `CompleteLessonResponse` only
 *      carries `hearts_remaining` and we want the full ratio.
 */
export function Summary({ result, lessonId, lessonTitle }: Props) {
  const [, navigate] = useLocation();

  // Mark the lesson done in localStorage — defensively, never throws.
  useEffect(() => {
    let cancelled = false;
    void (async () => {
      try {
        const mod = await import("@/lib/treeCompleted");
        if (!cancelled) mod.markCompleted(lessonId);
      } catch (e) {
        // eslint-disable-next-line no-console
        console.warn("[summary] markCompleted failed:", e);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [lessonId]);

  const heartsQ = useQuery<HeartsResponse>({
    queryKey: ["hearts"],
    queryFn: () => apiFetch<HeartsResponse>("/hearts"),
    // Use the just-graded value as a placeholder so we don't flash a stale
    // count from the cache.
    placeholderData: {
      hearts: result.hearts_remaining,
      max_hearts: 5,
      last_lost_at: null,
      regen_at: null,
    },
  });

  const hearts = heartsQ.data;
  const heartsDisplay = hearts
    ? hearts.max_hearts >= 100
      ? `${hearts.hearts} / ∞`
      : `${hearts.hearts} / ${hearts.max_hearts}`
    : `${result.hearts_remaining}`;

  const deltaBlock = formatLeagueDelta(result.league_rank_delta);

  return (
    <div className="relative flex h-full flex-col items-center gap-6 overflow-hidden px-2 pt-6">
      <Confetti />

      <h1 className="text-2xl font-bold text-slate-900">Урок завершён!</h1>
      <p className="-mt-3 text-sm text-slate-500">{lessonTitle}</p>

      {/* Big XP badge */}
      <div className="flex flex-col items-center gap-2 pt-2">
        <div className="flex h-32 w-32 items-center justify-center rounded-full bg-terracotta text-white shadow-card">
          <div className="flex flex-col items-center leading-none">
            <span className="text-4xl font-bold tabular-nums">+{result.xp_gained}</span>
            <span className="mt-1 text-xs font-semibold uppercase tracking-wide">XP</span>
          </div>
        </div>
        {result.perfect && (
          <span className="lg-pill bg-[#D4A21A]/15 text-[#A07A05]">⭐ Идеально</span>
        )}
      </div>

      {/* Stats grid */}
      <div className="flex w-full flex-col gap-3">
        <Card padding="md" className="flex items-center justify-between">
          <span className="text-sm text-slate-500">Сердечки</span>
          <span className="text-base font-semibold text-slate-900">{heartsDisplay} ❤️</span>
        </Card>
        <Card padding="md" className="flex items-center justify-between">
          <span className="text-sm text-slate-500">Стрик</span>
          <span className="text-base font-semibold text-slate-900">
            {result.streak} 🔥
          </span>
        </Card>
        {deltaBlock && (
          <Card padding="md" className="flex items-center justify-between">
            <span className="text-sm text-slate-500">Лига</span>
            <span className="text-base font-semibold text-slate-900">{deltaBlock}</span>
          </Card>
        )}
      </div>

      <div className="mt-auto w-full pb-4">
        <Button
          size="lg"
          className="w-full"
          onClick={() => navigate("/tree")}
          data-testid="summary-back"
        >
          На карту курса
        </Button>
      </div>
    </div>
  );
}

function formatLeagueDelta(delta: number | null): string | null {
  if (delta === null) return null;
  if (delta === 0) return "Без изменений";
  if (delta > 0) return `⬆ +${delta} в лиге`;
  return `⬇ ${delta} в лиге`;
}

/**
 * Pure-CSS confetti — a fixed set of triangle "petals" with a falling +
 * spin keyframe. No JS timers, no animation libs.
 */
function Confetti() {
  const colors = ["#E07856", "#D4A21A", "#3B6AC4", "#6FB8C9", "#C73762"];
  // Twelve pieces feels lively without thrashing the GPU on low-end Androids.
  const pieces = Array.from({ length: 12 }, (_, i) => ({
    left: (i / 12) * 100 + (i % 2 === 0 ? 3 : -3),
    delay: (i % 6) * 0.25,
    duration: 2.4 + (i % 4) * 0.4,
    color: colors[i % colors.length],
    rotate: (i * 47) % 360,
  }));

  return (
    <div aria-hidden="true" className="pointer-events-none absolute inset-0">
      <style>{`
        @keyframes lingomy-confetti-fall {
          0%   { transform: translate3d(0, -20%, 0) rotate(0deg); opacity: 0; }
          10%  { opacity: 1; }
          100% { transform: translate3d(0, 120%, 0) rotate(540deg); opacity: 0.85; }
        }
        @media (prefers-reduced-motion: reduce) {
          .lingomy-confetti-piece { animation: none !important; opacity: 0 !important; }
        }
      `}</style>
      {pieces.map((p, i) => (
        <span
          key={i}
          className="lingomy-confetti-piece absolute top-0 block h-2 w-2"
          style={{
            left: `${p.left}%`,
            backgroundColor: p.color,
            transform: `rotate(${p.rotate}deg)`,
            clipPath: "polygon(50% 0, 100% 100%, 0 100%)",
            animation: `lingomy-confetti-fall ${p.duration}s ease-in ${p.delay}s infinite`,
          }}
        />
      ))}
    </div>
  );
}
