import { Card } from "@/components/Card";

import { playAudio } from "../audio";

interface VocabIntroPayload {
  lemma?: string;
  translation_ru?: string;
  example_en?: string;
  example_ru?: string;
  audio_filename?: string;
}

interface Props {
  payload: VocabIntroPayload;
}

function SpeakerIcon({ className = "" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      aria-hidden="true"
    >
      <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
      <path d="M15.54 8.46a5 5 0 0 1 0 7.07" />
      <path d="M19.07 4.93a10 10 0 0 1 0 14.14" />
    </svg>
  );
}

/**
 * Vocab introduction card — flashcard, no real grading. The orchestrator
 * submits `answer=""` and the backend always returns `is_correct: true`.
 */
export function VocabIntro({ payload }: Props) {
  const audioFilename = payload.audio_filename;
  const onListen = (): void => {
    if (audioFilename) void playAudio(audioFilename);
  };

  return (
    <div className="flex flex-col items-center gap-4 pt-4">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Новое слово
      </p>
      <Card padding="lg" className="flex w-full flex-col items-center gap-3 text-center">
        <h2 className="text-3xl font-bold text-slate-900">{payload.lemma ?? "—"}</h2>
        {payload.translation_ru && (
          <p className="text-base text-slate-600">{payload.translation_ru}</p>
        )}
        {audioFilename && (
          <button
            type="button"
            onClick={onListen}
            className="mt-1 inline-flex items-center gap-2 rounded-full bg-terracotta px-5 py-2 text-sm font-semibold text-white shadow-sm active:scale-[0.98]"
          >
            <SpeakerIcon className="h-4 w-4" />
            Послушать
          </button>
        )}
      </Card>

      {(payload.example_en || payload.example_ru) && (
        <Card padding="md" className="flex w-full flex-col gap-1.5">
          {payload.example_en && (
            <p className="text-sm font-medium text-slate-900">{payload.example_en}</p>
          )}
          {payload.example_ru && (
            <p className="text-sm text-slate-600">{payload.example_ru}</p>
          )}
        </Card>
      )}
    </div>
  );
}
