import type { ButtonHTMLAttributes, ReactNode } from "react";

type Variant = "primary" | "secondary" | "ghost";
type Size = "sm" | "md" | "lg";

interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: Variant;
  size?: Size;
  children: ReactNode;
}

const VARIANT_CLS: Record<Variant, string> = {
  primary: "bg-terracotta text-white shadow-sm hover:bg-terracotta-600",
  secondary: "bg-white text-slate-900 border border-slate-200",
  ghost: "bg-transparent text-slate-700 hover:bg-cream-300/40",
};

const SIZE_CLS: Record<Size, string> = {
  sm: "h-9 px-4 text-sm",
  md: "h-11 px-5 text-base",
  lg: "h-12 px-6 text-base",
};

export function Button({
  variant = "primary",
  size = "md",
  className = "",
  children,
  ...rest
}: ButtonProps) {
  return (
    <button
      {...rest}
      className={`inline-flex items-center justify-center rounded-full font-semibold transition-transform active:scale-[0.98] disabled:opacity-50 disabled:active:scale-100 ${VARIANT_CLS[variant]} ${SIZE_CLS[size]} ${className}`}
    >
      {children}
    </button>
  );
}
