/**
 * Auth state — current user identity and JWT tokens.
 *
 * Persisted to localStorage so reopening the WebApp doesn't always require
 * a round-trip to /auth/telegram. The bootstrap flow (see lib/auth.ts)
 * decides whether to use the stored token, refresh it, or do a fresh login.
 */

import { create } from "zustand";
import type { TokenResponse, Tier } from "@/lib/types";

const STORAGE_KEY = "lingomy.auth.v1";

interface PersistedAuth {
  accessToken: string | null;
  refreshToken: string | null;
  accessExpiresAt: number | null;
  refreshExpiresAt: number | null;
  telegramId: number | null;
  tier: Tier | null;
}

interface AuthState extends PersistedAuth {
  setTokens: (t: TokenResponse) => void;
  clear: () => void;
}

function loadFromStorage(): PersistedAuth {
  if (typeof localStorage === "undefined") return emptyAuth();
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return emptyAuth();
    const parsed = JSON.parse(raw) as PersistedAuth;
    return {
      accessToken: parsed.accessToken ?? null,
      refreshToken: parsed.refreshToken ?? null,
      accessExpiresAt: parsed.accessExpiresAt ?? null,
      refreshExpiresAt: parsed.refreshExpiresAt ?? null,
      telegramId: parsed.telegramId ?? null,
      tier: parsed.tier ?? null,
    };
  } catch {
    return emptyAuth();
  }
}

function emptyAuth(): PersistedAuth {
  return {
    accessToken: null,
    refreshToken: null,
    accessExpiresAt: null,
    refreshExpiresAt: null,
    telegramId: null,
    tier: null,
  };
}

function persist(state: PersistedAuth): void {
  if (typeof localStorage === "undefined") return;
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch {
    /* quota or private mode — silently drop */
  }
}

export const useAuthStore = create<AuthState>((set) => ({
  ...loadFromStorage(),
  setTokens: (t: TokenResponse) => {
    const next: PersistedAuth = {
      accessToken: t.access_token,
      refreshToken: t.refresh_token,
      accessExpiresAt: t.access_expires_at,
      refreshExpiresAt: t.refresh_expires_at,
      telegramId: t.telegram_id,
      tier: t.tier,
    };
    persist(next);
    set(next);
  },
  clear: () => {
    const next = emptyAuth();
    persist(next);
    set(next);
  },
}));
