import { useEffect, useState } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { Redirect, Route, Router, Switch } from "wouter";

import { Profile } from "@/screens/Profile";
import { Tree } from "@/screens/Tree";
import { League } from "@/screens/League";
import { Friends } from "@/screens/Friends";
import { Lesson } from "@/screens/Lesson";
import { Loading } from "@/components/Loading";
import { BottomNav } from "@/components/BottomNav";
import { ErrorBox } from "@/components/ErrorBox";
import { ApiError } from "@/lib/api";
import { bootstrapAuth } from "@/lib/auth";
import { getInitData, initTelegram, isInsideTelegram } from "@/lib/twa";

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      retry: 1,
      staleTime: 30_000,
    },
  },
});

type AuthState =
  | { kind: "loading" }
  | { kind: "ready" }
  | { kind: "no-init-data" }
  | { kind: "error"; message: string };

function AuthGate({ children }: { children: React.ReactNode }) {
  const [state, setState] = useState<AuthState>({ kind: "loading" });

  useEffect(() => {
    let cancelled = false;

    async function run() {
      initTelegram();
      if (!getInitData()) {
        if (!cancelled) setState({ kind: "no-init-data" });
        return;
      }
      try {
        await bootstrapAuth();
        if (!cancelled) setState({ kind: "ready" });
      } catch (e) {
        if (cancelled) return;
        if (e instanceof ApiError && e.code === "NO_INIT_DATA") {
          setState({ kind: "no-init-data" });
        } else {
          setState({
            kind: "error",
            message: e instanceof Error ? e.message : "Не удалось войти",
          });
        }
      }
    }

    void run();
    return () => {
      cancelled = true;
    };
  }, []);

  if (state.kind === "loading") {
    return <Loading label="Подключаемся..." />;
  }

  if (state.kind === "no-init-data") {
    return (
      <ErrorBox
        title="Открой Lingomy в Telegram"
        message="Это приложение работает внутри Telegram. Зайди в бота и нажми кнопку в меню."
        hint={
          isInsideTelegram() ? null : (
            <span>
              Для локальной разработки задай <code>VITE_DEV_INIT_DATA</code> в{" "}
              <code>.env.local</code>.
            </span>
          )
        }
      />
    );
  }

  if (state.kind === "error") {
    return (
      <ErrorBox
        message={state.message}
        hint={<span>Попробуй переоткрыть Mini App из Telegram.</span>}
        onRetry={() => {
          setState({ kind: "loading" });
          void bootstrapAuth()
            .then(() => setState({ kind: "ready" }))
            .catch((e: unknown) =>
              setState({
                kind: "error",
                message: e instanceof Error ? e.message : "Ошибка входа",
              }),
            );
        }}
      />
    );
  }

  return <>{children}</>;
}

// Strip the trailing slash so wouter matches /profile (not /app//profile)
// when ``import.meta.env.BASE_URL`` is "/app/". Empty string = "/" root.
const ROUTER_BASE = (import.meta.env.BASE_URL || "/").replace(/\/$/, "");

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <div className="flex h-full flex-col">
        <AuthGate>
          <Router base={ROUTER_BASE}>
            <div className="flex flex-1 flex-col overflow-hidden">
              <Switch>
                <Route path="/profile" component={Profile} />
                <Route path="/tree" component={Tree} />
                <Route path="/league" component={League} />
                <Route path="/friends" component={Friends} />
                <Route path="/lessons/:id" component={Lesson} />
                <Route path="/">
                  <Redirect to="/tree" />
                </Route>
                <Route>
                  <Redirect to="/tree" />
                </Route>
              </Switch>
            </div>
            <BottomNav />
          </Router>
        </AuthGate>
      </div>
    </QueryClientProvider>
  );
}
