import type { ReactNode } from "react";

interface ErrorBoxProps {
  title?: string;
  message: string;
  hint?: ReactNode;
  onRetry?: () => void;
}

/**
 * Full-screen error state. Used when bootstrap fails or a screen-level
 * query errors out.
 */
export function ErrorBox({ title = "Что-то пошло не так", message, hint, onRetry }: ErrorBoxProps) {
  return (
    <div className="flex h-full flex-col items-center justify-center gap-3 px-6 text-center">
      <div className="text-4xl">😕</div>
      <h2 className="text-lg font-semibold text-slate-900">{title}</h2>
      <p className="max-w-xs text-sm text-slate-600">{message}</p>
      {hint && <div className="mt-2 max-w-xs text-xs text-slate-500">{hint}</div>}
      {onRetry && (
        <button
          type="button"
          onClick={onRetry}
          className="mt-4 rounded-full bg-terracotta px-5 py-2 text-sm font-semibold text-white shadow-sm active:scale-[0.98]"
        >
          Попробовать снова
        </button>
      )}
    </div>
  );
}
