import { useState } from "react";

import { useAuthStore } from "@/store/auth";
import { impactOccurred } from "@/lib/twa";

const INVITE_TEXT = "Учу английский в Lingomy — присоединяйся!";

/**
 * Best-effort base64url encoding of the inviter's `telegram_id`. Using URL-
 * safe alphabet so the `?start=` param survives without extra escaping.
 */
function encodeRef(id: number): string {
  const raw = String(id);
  const b64 =
    typeof btoa === "function" ? btoa(raw) : Buffer.from(raw, "utf-8").toString("base64");
  return b64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

function botUsername(): string {
  // VITE_BOT_USERNAME isn't typed in vite-env.d.ts (intentionally, to keep
  // this PR scoped to /friends). Read it dynamically with a safe default.
  const env = import.meta.env as Record<string, string | undefined>;
  return env.VITE_BOT_USERNAME ?? "LingomyBot";
}

function buildReferralLink(viewerId: number): string {
  return `https://t.me/${botUsername()}?start=friend_${encodeRef(viewerId)}`;
}

export function InviteCta() {
  const viewerId = useAuthStore((s) => s.telegramId);
  const [toast, setToast] = useState<string | null>(null);

  const onClick = () => {
    if (viewerId == null) return;
    impactOccurred("light");

    const link = buildReferralLink(viewerId);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const tg = (window as any).Telegram?.WebApp;

    if (tg?.switchInlineQuery) {
      try {
        tg.switchInlineQuery(INVITE_TEXT, ["users", "groups"]);
        return;
      } catch {
        // fall through to clipboard fallback
      }
    }

    const showToast = (msg: string) => {
      setToast(msg);
      window.setTimeout(() => setToast(null), 1500);
    };

    if (navigator.clipboard?.writeText) {
      void navigator.clipboard
        .writeText(link)
        .then(() => showToast("Ссылка скопирована"))
        .catch(() => showToast("Скопируй: " + link));
    } else {
      showToast("Скопируй: " + link);
    }
  };

  return (
    <div
      className="sticky bottom-0 -mx-4 mt-4 border-t border-slate-200/70 bg-cream-200/95 px-4 pb-3 pt-3 backdrop-blur"
      style={{ paddingBottom: "calc(0.75rem + var(--tg-safe-area-bottom))" }}
    >
      <button
        type="button"
        onClick={onClick}
        disabled={viewerId == null}
        className="flex h-12 w-full items-center justify-center rounded-full bg-terracotta px-6 text-base font-semibold text-white shadow-sm transition-transform active:scale-[0.98] disabled:opacity-50"
      >
        Пригласить друга
      </button>
      {toast && (
        <div
          role="status"
          className="pointer-events-none fixed inset-x-0 bottom-24 mx-auto w-fit max-w-[80%] rounded-full bg-slate-900/90 px-4 py-2 text-center text-xs text-white shadow-card"
        >
          {toast}
        </div>
      )}
    </div>
  );
}
