import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";

import { apiFetch } from "@/lib/api";
import { Card } from "@/components/Card";
import { Loading } from "@/components/Loading";
import { ErrorBox } from "@/components/ErrorBox";
import { useAuthStore } from "@/store/auth";
import { notificationOccurred } from "@/lib/twa";

import type { FriendshipOut } from "./types";
import { avatarLetter, displayName } from "./util";

export function PendingList() {
  const qc = useQueryClient();
  const viewerId = useAuthStore((s) => s.telegramId);

  const q = useQuery<FriendshipOut[]>({
    queryKey: ["friends", "pending"],
    queryFn: () => apiFetch<FriendshipOut[]>("/friends?status=pending"),
  });

  /**
   * Optimistic helpers — for both accept and decline we drop the row from
   * the cache immediately, then refetch on success. On failure we roll back
   * to the previous snapshot so the row reappears.
   */
  const acceptMut = useMutation({
    mutationFn: (id: number) =>
      apiFetch<FriendshipOut>(`/friends/${id}/accept`, { method: "POST" }),
    onMutate: async (id) => {
      await qc.cancelQueries({ queryKey: ["friends", "pending"] });
      const prev = qc.getQueryData<FriendshipOut[]>(["friends", "pending"]);
      qc.setQueryData<FriendshipOut[]>(["friends", "pending"], (old) =>
        (old ?? []).filter((r) => r.id !== id),
      );
      return { prev };
    },
    onError: (_e, _id, ctx) => {
      if (ctx?.prev) qc.setQueryData(["friends", "pending"], ctx.prev);
    },
    onSuccess: () => {
      notificationOccurred("success");
      void qc.invalidateQueries({ queryKey: ["friends"] });
    },
  });

  const declineMut = useMutation({
    mutationFn: (id: number) => apiFetch<void>(`/friends/${id}`, { method: "DELETE" }),
    onMutate: async (id) => {
      await qc.cancelQueries({ queryKey: ["friends", "pending"] });
      const prev = qc.getQueryData<FriendshipOut[]>(["friends", "pending"]);
      qc.setQueryData<FriendshipOut[]>(["friends", "pending"], (old) =>
        (old ?? []).filter((r) => r.id !== id),
      );
      return { prev };
    },
    onError: (_e, _id, ctx) => {
      if (ctx?.prev) qc.setQueryData(["friends", "pending"], ctx.prev);
    },
    onSuccess: () => {
      void qc.invalidateQueries({ queryKey: ["friends", "pending"] });
    },
  });

  if (q.isLoading) return <Loading label="Загрузка запросов..." />;
  if (q.error || !q.data) {
    return (
      <ErrorBox
        message={(q.error as Error)?.message ?? "Не удалось загрузить запросы"}
        onRetry={() => void q.refetch()}
      />
    );
  }

  // Only rows where the viewer is the invitee (i.e. friend_id === self).
  // If we don't yet know our telegram_id (very early bootstrap), show nothing
  // rather than rows we can't reason about.
  const rows = viewerId == null ? [] : q.data.filter((r) => r.friend_id === viewerId);

  if (rows.length === 0) {
    return (
      <Card padding="lg" className="text-center">
        <p className="text-sm text-slate-600">Никто не приглашал тебя 🙂</p>
      </Card>
    );
  }

  return (
    <ul className="flex flex-col gap-2">
      {rows.map((fs) => (
        <li key={fs.id}>
          <Card padding="md" className="flex items-center gap-3">
            <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-terracotta text-base font-bold text-white">
              {avatarLetter(fs.username, fs.user_id)}
            </div>
            <div className="flex min-w-0 flex-1 flex-col">
              <span className="truncate text-sm font-semibold text-slate-900">
                {displayName(fs.username, fs.user_id)}
              </span>
              <span className="text-xs text-slate-500">хочет дружить</span>
            </div>
            <div className="flex shrink-0 gap-2">
              <button
                type="button"
                disabled={acceptMut.isPending || declineMut.isPending}
                onClick={() => acceptMut.mutate(fs.id)}
                className="rounded-full bg-terracotta px-3.5 py-1.5 text-xs font-semibold text-white shadow-sm transition-transform active:scale-[0.98] disabled:opacity-50"
              >
                Принять
              </button>
              <button
                type="button"
                disabled={acceptMut.isPending || declineMut.isPending}
                onClick={() => declineMut.mutate(fs.id)}
                className="rounded-full border border-slate-200 bg-white px-3.5 py-1.5 text-xs font-semibold text-slate-900 transition-transform active:scale-[0.98] disabled:opacity-50"
              >
                Отклонить
              </button>
            </div>
          </Card>
        </li>
      ))}
    </ul>
  );
}
