import { Card } from "@/components/Card";

interface Payload {
  prompt_template?: string;
  options?: string[];
}

interface Props {
  payload: Payload;
  selectedOption: string | null;
  onPick: (option: string) => void;
  locked: boolean;
}

/**
 * Fill-in-the-blank — render the template with `___` replaced by either the
 * picked option (chip) or a visible placeholder; auto-submit on tap.
 */
export function FillBlank({ payload, selectedOption, onPick, locked }: Props) {
  const template = payload.prompt_template ?? "";
  const options = Array.isArray(payload.options) ? payload.options : [];

  // Split on the first `___` occurrence — backend only seeds a single blank.
  const splitIdx = template.indexOf("___");
  const before = splitIdx >= 0 ? template.slice(0, splitIdx) : template;
  const after = splitIdx >= 0 ? template.slice(splitIdx + 3) : "";

  return (
    <div className="flex flex-col gap-4 pt-2">
      <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
        Заполни пропуск
      </p>
      <Card padding="md" className="text-center">
        <p className="text-lg font-semibold text-slate-900">
          <span>{before}</span>
          <span
            className={`mx-1 inline-flex min-w-[3rem] items-center justify-center rounded-md px-2 py-0.5 align-baseline ${
              selectedOption
                ? "bg-terracotta text-white"
                : "border-b-2 border-dashed border-slate-400 text-transparent"
            }`}
          >
            {selectedOption ?? "___"}
          </span>
          <span>{after}</span>
        </p>
      </Card>
      <div className="flex flex-wrap gap-2">
        {options.map((opt, idx) => {
          const isPicked = selectedOption === opt;
          return (
            <button
              key={`${idx}-${opt}`}
              type="button"
              disabled={locked}
              onClick={() => onPick(opt)}
              data-testid={`fill-option-${idx}`}
              className={`flex-1 rounded-full border-2 px-4 py-2 text-sm font-semibold transition-colors active:scale-[0.98] disabled:opacity-60 disabled:active:scale-100 ${
                isPicked
                  ? "border-terracotta bg-terracotta text-white"
                  : "border-slate-200 bg-white text-slate-900"
              }`}
            >
              {opt}
            </button>
          );
        })}
      </div>
    </div>
  );
}
