/**
 * Local persistence of "lessons the user has completed".
 *
 * The backend `/me` endpoint does not (yet) return the user's completed set.
 * Until it does, the Tree screen reads completion state from localStorage and
 * the Lesson screen writes to it on success.
 *
 * NEXT ITERATION: swap these helpers with a server-side query (likely
 * `/me/lessons/completed` returning `number[]`) and keep the same signature.
 *
 * Key: `lingomy.tree.completed` — JSON-encoded `number[]`.
 */

const STORAGE_KEY = "lingomy.tree.completed";

function readRaw(): number[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return [];
    const parsed: unknown = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed.filter((x): x is number => typeof x === "number" && Number.isFinite(x));
  } catch {
    return [];
  }
}

function writeRaw(ids: Iterable<number>): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(Array.from(new Set(ids))));
  } catch {
    /* quota exceeded or storage unavailable — ignore */
  }
}

/** Returns the set of completed lesson IDs. Cheap; safe to call on every render. */
export function getCompleted(): Set<number> {
  return new Set(readRaw());
}

/** Marks `lessonId` as completed. Idempotent. */
export function markCompleted(lessonId: number): void {
  const current = new Set(readRaw());
  current.add(lessonId);
  writeRaw(current);
}

/**
 * Subscribe to "the user came back to this tab" events. We invoke `cb` whenever
 * the document becomes visible again (likely after finishing a lesson on
 * another screen) and whenever a `storage` event for our key arrives.
 * Returns an unsubscribe function.
 */
export function subscribe(cb: () => void): () => void {
  const onVisible = (): void => {
    if (document.visibilityState === "visible") cb();
  };
  const onStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) cb();
  };
  document.addEventListener("visibilitychange", onVisible);
  window.addEventListener("storage", onStorage);
  return () => {
    document.removeEventListener("visibilitychange", onVisible);
    window.removeEventListener("storage", onStorage);
  };
}
